/* ---------------------------------- local persistence (standalone build only) ---------------------------------- */
function loadState(key, fallback) {
  try {
    const raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) : fallback;
  } catch (e) {
    return fallback;
  }
}
function saveState(key, value) {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch (e) {
    /* storage unavailable (private browsing, quota, etc.) — fail silently */
  }
}

/* ---------------------------------- cross-device sync (Firestore, falls back to local-only) ---------------------------------- */
function useSyncedState(storageKey, fallback) {
  const [value, setValue] = useState(() => loadState(storageKey, fallback));
  const [ready, setReady] = useState(false);
  const lastRemoteJson = useRef(null);

  // push local changes to the cloud, and always keep a local cache for instant/offline loads.
  // Critically, this NEVER fires until `ready` is true — i.e. until we've confirmed what the
  // cloud actually has. Otherwise, a fresh/cleared browser could push blank local defaults up
  // and clobber real data before the real cloud data has had a chance to load in.
  useEffect(() => {
    saveState(storageKey, value);
    if (!ready) return;
    const json = JSON.stringify(value);
    if (json === lastRemoteJson.current) return; // this update came FROM the cloud — don't echo it back
    if (window.__musorichoSetDoc) window.__musorichoSetDoc(storageKey, json);
  }, [value, ready]);

  // listen for changes made from other devices
  useEffect(() => {
    let unsub = null;
    let cancelled = false;
    const subscribe = () => {
      unsub = window.__musorichoOnSnapshot(storageKey, (json, isError) => {
        if (isError) {
          // couldn't confirm what the cloud actually has (offline, not signed in with Google,
          // permission denied, etc). Show local data for now, but do NOT treat this as "cloud is
          // empty" — that would push our local (possibly blank, on a device that's never synced
          // before) state up and clobber real data belonging to everyone else. Just wait it out;
          // the listener will fire again once a real connection/permission is established.
          setReady(true);
          return;
        }
        if (json !== null) {
          // cloud already has data — always trust it over whatever's in local fallback
          lastRemoteJson.current = json;
          try { setValue(JSON.parse(json)); } catch (e) { /* ignore malformed cloud data */ }
        } else {
          // cloud CONFIRMED there's genuinely no document yet (brand-new setup) — safe to seed it from local
          setValue(current => {
            const seedJson = JSON.stringify(current);
            lastRemoteJson.current = seedJson;
            if (window.__musorichoSetDoc) window.__musorichoSetDoc(storageKey, seedJson);
            return current;
          });
        }
        setReady(true); // confirmed: this reflects the cloud's current state (even if the doc is empty/new)
      });
    };
    if (window.__musorichoOnSnapshot) {
      subscribe();
    } else {
      const handler = () => subscribe();
      window.addEventListener("musoricho-firebase-ready", handler, { once: true });
      const timeout = setTimeout(() => { if (!cancelled) setReady(true); }, 5000); // cloud unreachable — proceed with local data
      return () => { window.removeEventListener("musoricho-firebase-ready", handler); clearTimeout(timeout); cancelled = true; };
    }
    return () => { if (unsub) unsub(); };
  }, []);

  return [value, setValue, ready];
}

