const fmtKES = (n) =>
  "KES " + Number(n || 0).toLocaleString("en-KE", { minimumFractionDigits: 0, maximumFractionDigits: 0 });

// Returns the real Date a sale happened. Sales created by the current app always have a `ts`
// (epoch millis) — but older records synced in from before that field existed only have the
// printed `date`/`time` strings (en-KE locale, "DD/MM/YYYY" + "HH:MM"). Falling back to "now"
// for those silently miscategorizes old sales as happening today, so we parse the strings instead.
function saleTimestamp(s) {
  if (s.ts) return new Date(s.ts);
  if (s.date) {
    const [d, m, y] = s.date.split("/").map(Number);
    if (d && m && y) {
      let hh = 0, mm = 0;
      if (s.time) {
        const [h, min] = s.time.split(":").map(Number);
        if (!isNaN(h)) hh = h;
        if (!isNaN(min)) mm = min;
      }
      return new Date(y, m - 1, d, hh, mm);
    }
  }
  return new Date(0); // truly unknown — treat as very old rather than falsely "today"
}

/* ---------------------------------- logo raster for thermal printing ---------------------------------- */
// Converts the inline LOGO_DATA_URI into a 1-bit monochrome ESC/POS raster image
// (GS v 0 command), so the brand logo prints at the top of Bluetooth thermal receipts.
let _logoRasterCache = null;
function _loadImageEl(src) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = reject;
    img.src = src;
  });
}
async function getLogoEscPosRaster(targetWidthPx = 192) {
  if (_logoRasterCache) return _logoRasterCache;
  try {
    const img = await _loadImageEl(LOGO_DATA_URI);
    const scale = targetWidthPx / img.width;
    const w = targetWidthPx;
    const h = Math.max(1, Math.round(img.height * scale));
    const canvas = document.createElement("canvas");
    canvas.width = w; canvas.height = h;
    const ctx = canvas.getContext("2d");
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, w, h);
    ctx.drawImage(img, 0, 0, w, h);
    const { data } = ctx.getImageData(0, 0, w, h);
    const bytesPerRow = Math.ceil(w / 8);
    const raster = new Uint8Array(bytesPerRow * h);
    for (let y = 0; y < h; y++) {
      for (let x = 0; x < w; x++) {
        const idx = (y * w + x) * 4;
        const a = data[idx + 3];
        const lum = 0.299 * data[idx] + 0.587 * data[idx + 1] + 0.114 * data[idx + 2];
        if (a > 128 && lum < 128) {
          raster[y * bytesPerRow + (x >> 3)] |= (0x80 >> (x & 7));
        }
      }
    }
    const header = [0x1D, 0x76, 0x30, 0x00, bytesPerRow & 0xFF, (bytesPerRow >> 8) & 0xFF, h & 0xFF, (h >> 8) & 0xFF];
    const result = new Uint8Array(header.length + raster.length);
    result.set(header, 0);
    result.set(raster, header.length);
    _logoRasterCache = result;
    return result;
  } catch (e) {
    return new Uint8Array(0); // if it can't be rendered, just skip the logo gracefully
  }
}

/* ---------------------------------- Bluetooth thermal printing (ESC/POS) ---------------------------------- */
// Common service/characteristic UUIDs used by generic BLE thermal printers (P58E and similar clones).
const BT_PRINTER_SERVICES = [
  "000018f0-0000-1000-8000-00805f9b34fb",
  "0000ff00-0000-1000-8000-00805f9b34fb",
  "0000ffe0-0000-1000-8000-00805f9b34fb",
  "49535343-fe7d-4ae5-8fa9-9fafd205e455",
  "e7810a71-73ae-499d-8c15-faa9aef0c3f2",
];

async function connectBluetoothPrinter() {
  if (!navigator.bluetooth) {
    throw new Error("Bluetooth printing needs Chrome on Android (or desktop Chrome). This browser doesn't support it.");
  }
  const device = await navigator.bluetooth.requestDevice({
    acceptAllDevices: true,
    optionalServices: BT_PRINTER_SERVICES,
  });
  const server = await device.gatt.connect();
  const services = await server.getPrimaryServices();
  let writable = null;
  for (const service of services) {
    const chars = await service.getCharacteristics();
    for (const c of chars) {
      if (c.properties.write || c.properties.writeWithoutResponse) { writable = c; break; }
    }
    if (writable) break;
  }
  if (!writable) throw new Error("Connected, but couldn't find a printable channel on this device.");
  return { device, characteristic: writable, name: device.name || "Bluetooth Printer" };
}

async function writeBytesToPrinter(characteristic, bytes) {
  const chunkSize = 20; // conservative BLE MTU for older printer chipsets
  for (let i = 0; i < bytes.length; i += chunkSize) {
    const chunk = bytes.slice(i, i + chunkSize);
    if (characteristic.properties.writeWithoutResponse) {
      await characteristic.writeValueWithoutResponse(chunk);
    } else {
      await characteristic.writeValue(chunk);
    }
    await new Promise(r => setTimeout(r, 20));
  }
}

// Build raw ESC/POS bytes for a 58mm printer (32-character line width).
async function buildEscPosReceipt(sale, businessInfo) {
  const WIDTH = 32;
  const enc = new TextEncoder();
  const bytes = [];
  const push = (arr) => bytes.push(...arr);
  const text = (s) => push(Array.from(enc.encode(s)));
  const center = (on) => push([0x1B, 0x61, on ? 1 : 0]);
  const bold = (on) => push([0x1B, 0x45, on ? 1 : 0]);
  const line = (s = "") => { text(s); push([0x0A]); };
  const rule = () => line("-".repeat(WIDTH));
  const twoCol = (l, r) => {
    l = String(l); r = String(r);
    const gap = Math.max(1, WIDTH - l.length - r.length);
    line(l + " ".repeat(gap) + r);
  };

  push([0x1B, 0x40]); // init
  center(true);
  const logoRaster = await getLogoEscPosRaster();
  if (logoRaster.length) { push(Array.from(logoRaster)); push([0x0A]); }
  bold(true);
  line(businessInfo.name);
  bold(false);
  line(businessInfo.address);
  line(businessInfo.phone);
  line("Till: " + businessInfo.till);
  center(false);
  rule();
  twoCol("Receipt#", sale.id);
  twoCol("Date", `${sale.date} ${sale.time}`);
  twoCol("Cashier", sale.cashier);
  twoCol("Customer", sale.customer);
  rule();
  sale.items.forEach(it => {
    line(it.name.slice(0, WIDTH));
    if (it.category) line(`  ${it.category}`.slice(0, WIDTH));
    twoCol(`${it.qty} x ${fmtKES(it.price)}`, fmtKES(it.qty * it.price));
  });
  rule();
  twoCol("Subtotal", fmtKES(sale.subtotal));
  twoCol("Discount", "-" + fmtKES(sale.discountAmt));
  twoCol(`VAT (${sale.vatPct ?? 16}%)`, fmtKES(sale.vat));
  bold(true);
  twoCol("TOTAL", fmtKES(sale.total));
  bold(false);
  twoCol("Paid via", sale.method);
  rule();
  center(true);
  line("Thank You for Shopping With Us");
  line("Drink responsibly");
  center(false);
  push([0x0A, 0x0A, 0x0A, 0x0A]);
  push([0x1D, 0x56, 66, 0]); // partial cut (ignored if unsupported)
  return new Uint8Array(bytes);
}

