/* ---------------------------------- app ---------------------------------- */
function App() {
  const [dark, setDark] = useState(false);
  const [authUser, setAuthUser] = useState(null); // { email, name, photo, uid } | null
  const [firebaseReady, setFirebaseReady] = useState(() => !!window.__musorichoOnAuthChange);
  const [authStatus, setAuthStatus] = useState("checking"); // checking | signed-out | signing-in | signed-in | denied | error
  const [authError, setAuthError] = useState("");
  const [role, setRole] = useState(null);
  const [cashierName, setCashierName] = useState("");
  const [view, setView] = useState("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const [products, setProducts] = useSyncedState("musoricho_products", initialProducts);
  const [categories, setCategories] = useSyncedState("musoricho_categories", CATEGORIES);
  const [staffAccounts, setStaffAccounts, staffAccountsReady] = useSyncedState("musoricho_staff_accounts", {}); // { email: role }
  const [customers, setCustomers] = useSyncedState("musoricho_customers", initialCustomers);
  const [transactions, setTransactions] = useSyncedState("musoricho_transactions", initialTransactions);
  const [sales, setSales] = useSyncedState("musoricho_sales", []);
  const [expenses, setExpenses] = useSyncedState("musoricho_expenses", []);
  const [businessInfo, setBusinessInfo] = useSyncedState("musoricho_business_info", {
    name: "MUSORICHO WINES & SPIRITS",
    currency: "KES",
    vatRate: 16,
    till: "000000",
    phone: "0722 000 000",
    address: "Moi Avenue, Nairobi",
  });

  const [cart, setCart] = useState(() => loadState("musoricho_cart_draft", []));
  useEffect(() => { saveState("musoricho_cart_draft", cart); }, [cart]);
  const [discountPct, setDiscountPct] = useState(() => loadState("musoricho_discount_draft", 0));
  useEffect(() => { saveState("musoricho_discount_draft", discountPct); }, [discountPct]);
  const [payMethod, setPayMethod] = useState(() => loadState("musoricho_paymethod_draft", "Cash"));
  useEffect(() => { saveState("musoricho_paymethod_draft", payMethod); }, [payMethod]);
  const [customerId, setCustomerId] = useState(() => loadState("musoricho_customerid_draft", 1));
  useEffect(() => { saveState("musoricho_customerid_draft", customerId); }, [customerId]);
  const [receipt, setReceipt] = useState(null);
  const [productModal, setProductModal] = useState(null); // {mode:'add'|'edit', data}
  const [stockModal, setStockModal] = useState(null);
  const [toast, setToast] = useState(null);
  const [printer, setPrinter] = useState(null); // { device, characteristic, name }

  const t = dark
    ? { bg: palette.charcoalBg, surface: palette.charcoalSurface, text: "#F3EEF6", sub: "#B8ACC2", border: "#3A2E42" }
    : { bg: palette.creamBg, surface: palette.creamSurface, text: palette.ink, sub: "#6B5D72", border: "#E7DFE9" };

  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(null), 2200); };

  // watch Firebase auth state; resolve the signed-in Google account against staffAccounts
  useEffect(() => {
    let unsub = null;
    const attach = () => {
      setFirebaseReady(true);
      unsub = window.__musorichoOnAuthChange((user) => {
        setAuthUser(user);
        if (!user) { setAuthStatus("signed-out"); setRole(null); setCashierName(""); return; }
      });
    };
    if (window.__musorichoOnAuthChange) attach();
    else window.addEventListener("musoricho-firebase-ready", attach, { once: true });
    return () => { if (unsub) unsub(); };
  }, []);

  // once we know both who signed in AND the staff roster, decide access
  useEffect(() => {
    if (!authUser || !staffAccountsReady) return;
    const email = authUser.email.toLowerCase();
    const knownEmails = Object.keys(staffAccounts).map(e => e.toLowerCase());

    if (knownEmails.length === 0) {
      // bootstrap: first person ever to sign in becomes Administrator
      setStaffAccounts(sa => (Object.keys(sa).length === 0 ? { [authUser.email]: "Administrator" } : sa));
      setRole("Administrator");
      setCashierName(authUser.name || authUser.email);
      setAuthStatus("signed-in");
      return;
    }
    const matchKey = Object.keys(staffAccounts).find(e => e.toLowerCase() === email);
    if (matchKey) {
      setRole(staffAccounts[matchKey]);
      setCashierName(authUser.name || authUser.email);
      setAuthStatus("signed-in");
    } else {
      setRole(null);
      setAuthStatus("denied");
    }
  }, [authUser, staffAccounts]);

  const friendlyAuthError = (e) => {
    const code = e && e.code;
    const map = {
      "auth/invalid-email": "That doesn't look like a valid email address.",
      "auth/user-not-found": "No account found with that email.",
      "auth/wrong-password": "Incorrect password.",
      "auth/invalid-credential": "Incorrect email or password.",
      "auth/email-already-in-use": "An account with that email already exists — try signing in instead.",
      "auth/weak-password": "Password should be at least 6 characters.",
      "auth/too-many-requests": "Too many attempts. Please wait a moment and try again.",
      "auth/popup-closed-by-user": "Sign-in was cancelled.",
      "auth/popup-blocked": "Your browser blocked the sign-in popup. Please allow popups for this site and try again.",
      "auth/cancelled-popup-request": "Sign-in was cancelled.",
      "auth/missing-initial-state": "Your browser blocked the sign-in flow — this is common with Brave Shields or strict privacy settings. Try turning off Brave Shields for this site (or use Chrome), then try again.",
      "auth/unauthorized-domain": "This site isn't authorized for sign-in yet. Ask your administrator to check the Firebase console settings.",
      "auth/operation-not-supported-in-this-environment": "Sign-in isn't supported in this browser environment. Try a different browser.",
      "auth/web-storage-unsupported": "Your browser is blocking storage needed to sign in. Try disabling private/incognito mode or shields for this site.",
    };
    return (code && map[code]) || (e && e.message) || "Something went wrong. Please try again.";
  };

  // catches errors from the Google popup sign-in flow
  useEffect(() => {
    const handler = (e) => {
      setAuthStatus("error");
      setAuthError(friendlyAuthError(e.detail || {}));
    };
    window.addEventListener("musoricho-auth-error", handler);
    return () => window.removeEventListener("musoricho-auth-error", handler);
  }, []);

  const NOT_READY_MSG = "Still connecting to sign-in services — please wait a moment and try again.";

  const handleSignIn = async () => {
    if (!window.__musorichoSignIn) { setAuthStatus("error"); setAuthError(NOT_READY_MSG); return; }
    setAuthStatus("signing-in"); setAuthError("");
    try {
      // resolves directly with the signed-in user via a popup — no page navigation/reload involved,
      // so onAuthStateChanged (registered above) will also fire shortly with the same result.
      await window.__musorichoSignIn();
    } catch (e) {
      setAuthStatus("error");
      setAuthError(friendlyAuthError(e));
    }
  };

  const handleSignOut = async () => {
    if (window.__musorichoSignOut) { try { await window.__musorichoSignOut(); } catch (e) { /* ignore */ } }
    setRole(null); setCashierName(""); setAuthUser(null); setAuthStatus("signed-out");
  };

  const connectPrinter = async () => {
    try {
      const conn = await connectBluetoothPrinter();
      conn.device.addEventListener("gattserverdisconnected", () => { setPrinter(null); showToast("Printer disconnected"); });
      setPrinter(conn);
      showToast(`Connected to ${conn.name}`);
    } catch (e) {
      showToast(e.message || "Couldn't connect to printer");
    }
  };
  const disconnectPrinter = () => {
    if (printer?.device?.gatt?.connected) printer.device.gatt.disconnect();
    setPrinter(null);
    showToast("Printer disconnected");
  };
  const printViaBluetooth = async (sale) => {
    try {
      let conn = printer;
      if (!conn || !conn.device.gatt.connected) {
        conn = await connectBluetoothPrinter();
        conn.device.addEventListener("gattserverdisconnected", () => { setPrinter(null); showToast("Printer disconnected"); });
        setPrinter(conn);
      }
      const bytes = await buildEscPosReceipt(sale, businessInfo);
      await writeBytesToPrinter(conn.characteristic, bytes);
      showToast("Sent to printer");
    } catch (e) {
      showToast(e.message || "Bluetooth print failed");
    }
  };

  if (!role) {
    return <Login t={t} dark={dark} setDark={setDark} onSignIn={handleSignIn} authStatus={authStatus} authError={authError} />;
  }

  const lowStock = products.filter(p => p.qty > 0 && p.qty <= p.min);
  const outStock = products.filter(p => p.qty === 0);

  const nav = [
    { id: "dashboard", label: "Dashboard", icon: LayoutDashboard },
    { id: "pos", label: "New Sale", icon: ShoppingCart },
    { id: "products", label: "Products", icon: Wine },
    { id: "inventory", label: "Inventory", icon: Boxes },
    { id: "expenses", label: "Expenses", icon: Receipt },
    { id: "reports", label: "Reports", icon: BarChart3 },
    { id: "customers", label: "Customers", icon: Users },
    { id: "settings", label: "Settings", icon: SettingsIcon },
  ];

  return (
    <div style={{ background: t.bg, color: t.text, minHeight: "100vh", fontFamily: "-apple-system, Inter, Segoe UI, sans-serif" }}>
      <style>{`
        * { box-sizing: border-box; }
        html, body, #root { width: 100%; height: 100%; }
        .serif { font-family: Georgia, 'Times New Roman', serif; }
        ::-webkit-scrollbar { width: 8px; height: 8px; }
        ::-webkit-scrollbar-thumb { background: ${palette.wineLight}55; border-radius: 8px; }
        button:focus-visible, input:focus-visible, select:focus-visible { outline: 2px solid ${palette.gold}; outline-offset: 1px; }
        button { transition: transform 0.1s ease, filter 0.1s ease, opacity 0.1s ease; }
        button:active:not(:disabled) { transform: scale(0.95); filter: brightness(0.92); }
        button:disabled { cursor: not-allowed; }
        .app-shell { display: flex; min-height: 100vh; width: 100%; }
        .sidebar { flex-shrink: 0; overflow: hidden; transition: width 0.22s ease, padding 0.22s ease; white-space: nowrap; }
        .main-col { flex: 1; min-width: 0; display: flex; flex-direction: column; width: 100%; }
        .content-pad { padding: 28px 40px; flex: 1; overflow-y: auto; width: 100%; max-width: 1600px; margin: 0 auto; }
        .topbar { padding: 16px 40px; }
        .card-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(170px,1fr)); gap: 14px; }
        .pos-grid { display: grid; grid-template-columns: minmax(0,1fr) 360px; gap: 18px; height: calc(100vh - 160px); }
        .pos-products { display: grid; grid-template-columns: repeat(auto-fill, minmax(160px,1fr)); gap: 12px; }
        .two-col { display: grid; grid-template-columns: 1fr 1fr; gap: 18px; }
        .two-col-wide { display: grid; grid-template-columns: 1.4fr 1fr; gap: 18px; }
        .four-col { display: grid; grid-template-columns: repeat(4,1fr); gap: 14px; }
        @media (max-width: 980px) {
          .content-pad, .topbar { padding-left: 18px; padding-right: 18px; }
          .pos-grid { grid-template-columns: minmax(0,1fr); height: auto; }
          .two-col, .two-col-wide, .four-col { grid-template-columns: 1fr; }
          .scroll-hint { display: block; }
        }
        .scroll-hint { display: none; font-size: 11px; color: ${t.sub}; padding: 6px 14px 0; }
      `}</style>

      <div className="app-shell">
        {/* Sidebar */}
        <div className="sidebar" style={{ width: sidebarOpen ? 236 : 0, padding: sidebarOpen ? "22px 14px" : "22px 0", background: `linear-gradient(180deg, ${palette.wineDeep}, ${palette.wine})`, color: "#F3EEF6", display: "flex", flexDirection: "column" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "0 8px 22px", borderBottom: "1px solid #ffffff22", marginBottom: 18 }}>
            <div style={{ width: 36, height: 36, borderRadius: 8, background: "#ffffff", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, padding: 4 }}>
              <img src={LOGO_DATA_URI} alt="MUSORICHO logo" style={{ maxWidth: "100%", maxHeight: "100%", width: "auto", height: "auto", objectFit: "contain", display: "block" }} />
            </div>

            <div className="brand-text" style={{ flex: 1 }}>
              <div className="serif" style={{ fontSize: 15, fontWeight: 700, letterSpacing: 0.3, whiteSpace: "nowrap" }}>MUSORICHO</div>
              <div style={{ fontSize: 9.5, letterSpacing: 1.5, color: palette.goldSoft, whiteSpace: "nowrap" }}>WINES &amp; SPIRITS</div>
            </div>
            <button onClick={() => setSidebarOpen(false)} title="Collapse menu" style={{ background: "transparent", border: "none", color: "#E6D9E8", cursor: "pointer", padding: 4, flexShrink: 0 }}>
              <PanelLeftClose size={17} />
            </button>
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 3, flex: 1 }}>
            {nav.map(n => {
              if (n.id === "settings" && role !== "Administrator") return null;
              const Icon = n.icon;
              const active = view === n.id;
              return (
                <button key={n.id} onClick={() => setView(n.id)} title={n.label}
                  style={{
                    display: "flex", alignItems: "center", gap: 10, padding: "9px 10px", borderRadius: 8, border: "none",
                    background: active ? "#ffffff1c" : "transparent", color: active ? "#fff" : "#E6D9E8",
                    cursor: "pointer", fontSize: 13.5, fontWeight: active ? 600 : 500, textAlign: "left"
                  }}>
                  <Icon size={16} style={{ flexShrink: 0 }} /> <span className="nav-label">{n.label}</span>
                  {n.id === "inventory" && (lowStock.length + outStock.length > 0) && (
                    <span className="nav-label" style={{ marginLeft: "auto", background: palette.danger, borderRadius: 20, fontSize: 10, padding: "1px 6px" }}>
                      {lowStock.length + outStock.length}
                    </span>
                  )}
                </button>
              );
            })}
          </div>
          <div style={{ borderTop: "1px solid #ffffff22", paddingTop: 12, marginTop: 12 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "0 8px 10px" }}>
              <UserCircle2 size={22} color={palette.goldSoft} style={{ flexShrink: 0 }} />
              <div className="user-text">
                <div style={{ fontSize: 12.5, fontWeight: 600, whiteSpace: "nowrap" }}>{cashierName}</div>
                <div style={{ fontSize: 10.5, color: "#C9B9CC", whiteSpace: "nowrap" }}>{role}</div>
              </div>
            </div>
            <button onClick={handleSignOut} title="Sign out" style={{ display: "flex", alignItems: "center", gap: 8, width: "100%", padding: "8px 8px", background: "transparent", border: "none", color: "#E6D9E8", fontSize: 12.5, cursor: "pointer" }}>
              <LogOut size={14} style={{ flexShrink: 0 }} /> <span className="nav-label">Sign out</span>
            </button>
          </div>
        </div>

        {/* Main */}
        <div className="main-col">
          <div className="topbar" style={{ display: "flex", alignItems: "center", justifyContent: "space-between", borderBottom: `1px solid ${t.border}`, background: t.surface }}>
            <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
              {!sidebarOpen && (
                <button onClick={() => setSidebarOpen(true)} title="Open menu" style={{ width: 34, height: 34, borderRadius: 8, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                  <Menu size={16} />
                </button>
              )}
              <div>
                <div className="serif" style={{ fontSize: 18, fontWeight: 700 }}>{nav.find(n => n.id === view)?.label}</div>
                <div style={{ fontSize: 11.5, color: t.sub }}>{new Date().toLocaleDateString("en-KE", { weekday: "long", year: "numeric", month: "long", day: "numeric" })}</div>
              </div>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
              {(outStock.length > 0) && (
                <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 12, color: palette.danger, background: `${palette.danger}18`, padding: "6px 10px", borderRadius: 8, whiteSpace: "nowrap" }}>
                  <AlertTriangle size={13} /> {outStock.length} out of stock
                </div>
              )}
              <button onClick={() => setDark(d => !d)} style={{ width: 34, height: 34, borderRadius: 8, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                {dark ? <Sun size={16} /> : <Moon size={16} />}
              </button>
            </div>
          </div>

          <div className="content-pad">
            {view === "dashboard" && <Dashboard t={t} products={products} lowStock={lowStock} outStock={outStock} customers={customers} transactions={transactions} sales={sales} expenses={expenses} setReceipt={setReceipt} />}
            {view === "pos" && (
              <POS t={t} products={products} setProducts={setProducts} cart={cart} setCart={setCart}
                categories={categories} role={role}
                discountPct={discountPct} setDiscountPct={setDiscountPct} payMethod={payMethod} setPayMethod={setPayMethod}
                customerId={customerId} setCustomerId={setCustomerId}
                customers={customers} cashierName={cashierName} businessInfo={businessInfo}
                onComplete={(sale) => {
                  setTransactions(tx => [{ id: sale.id, time: sale.time, cashier: cashierName, items: sale.items.length, total: sale.total, method: sale.method }, ...tx]);
                  setSales(s => [...s, sale]);
                  setReceipt(sale);
                  setCart([]); setDiscountPct(0); setCustomerId(1);
                  showToast(`Sale ${sale.id} completed`);
                }} />
            )}
            {view === "products" && <Products t={t} products={products} setProducts={setProducts} categories={categories} setCategories={setCategories} onEdit={(p) => setProductModal({ mode: "edit", data: p })} onAdd={() => setProductModal({ mode: "add", data: null })} showToast={showToast} role={role} />}
            {view === "inventory" && <Inventory t={t} products={products} setProducts={setProducts} lowStock={lowStock} outStock={outStock} onStockIn={(p) => setStockModal(p)} showToast={showToast} role={role} />}
            {view === "expenses" && <Expenses t={t} expenses={expenses} setExpenses={setExpenses} showToast={showToast} role={role} />}
            {view === "reports" && <Reports t={t} products={products} sales={sales} setSales={setSales} transactions={transactions} setTransactions={setTransactions} showToast={showToast} role={role} setReceipt={setReceipt} expenses={expenses} />}
            {view === "customers" && <Customers t={t} customers={customers} setCustomers={setCustomers} showToast={showToast} role={role} />}
            {view === "settings" && <SettingsPanel t={t} role={role} businessInfo={businessInfo} setBusinessInfo={setBusinessInfo} showToast={showToast} printer={printer} connectPrinter={connectPrinter} disconnectPrinter={disconnectPrinter}
              products={products} setProducts={setProducts} categories={categories} setCategories={setCategories} customers={customers} setCustomers={setCustomers}
              transactions={transactions} setTransactions={setTransactions} sales={sales} setSales={setSales} expenses={expenses} setExpenses={setExpenses}
              staffAccounts={staffAccounts} setStaffAccounts={setStaffAccounts} currentUserEmail={authUser?.email} />}
          </div>
        </div>
      </div>

      {receipt && <ReceiptModal t={t} sale={receipt} businessInfo={businessInfo} printer={printer} printViaBluetooth={printViaBluetooth} onClose={() => setReceipt(null)} />}
      {productModal && (
        <ProductModal t={t} mode={productModal.mode} data={productModal.data} categories={categories} setCategories={setCategories}
          onClose={() => setProductModal(null)}
          onSave={(p) => {
            setProducts(list => productModal.mode === "add"
              ? [...list, { ...p, id: Math.max(0, ...list.map(x => x.id)) + 1 }]
              : list.map(x => x.id === p.id ? p : x));
            setProductModal(null);
            showToast(productModal.mode === "add" ? "Product added" : "Product updated");
          }} />
      )}
      {stockModal && (
        <StockInModal t={t} product={stockModal} onClose={() => setStockModal(null)}
          onConfirm={(qty) => {
            setProducts(list => list.map(p => p.id === stockModal.id ? { ...p, qty: p.qty + qty } : p));
            setStockModal(null); showToast(`Added ${qty} units to ${stockModal.name}`);
          }} />
      )}
      {toast && (
        <div style={{ position: "fixed", bottom: 24, left: "50%", transform: "translateX(-50%)", display: "flex", alignItems: "center", gap: 8, background: palette.ink, color: "#fff", padding: "11px 20px", borderRadius: 9, fontSize: 13, fontWeight: 500, boxShadow: "0 10px 30px #0006", zIndex: 200, animation: "toastIn 0.18s ease" }}>
          <span style={{ width: 16, height: 16, borderRadius: "50%", background: palette.gold, color: palette.wineDeep, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 900, flexShrink: 0 }}>✓</span>
          {toast}
        </div>
      )}
      <style>{`@keyframes toastIn { from { opacity: 0; transform: translate(-50%, 10px); } to { opacity: 1; transform: translate(-50%, 0); } }`}</style>
    </div>
  );
}

/* ---------------------------------- login ---------------------------------- */
const GoogleIcon = ({ size = 18 }) => (
  <svg width={size} height={size} viewBox="0 0 48 48" style={{ flexShrink: 0 }}>
    <path fill="#FFC107" d="M43.611,20.083H42V20H24v8h11.303c-1.649,4.657-6.08,8-11.303,8c-6.627,0-12-5.373-12-12 s5.373-12,12-12c3.059,0,5.842,1.154,7.961,3.039l5.657-5.657C34.046,6.053,29.268,4,24,4C12.955,4,4,12.955,4,24 s8.955,20,20,20s20-8.955,20-20C44,22.659,43.862,21.35,43.611,20.083z"/>
    <path fill="#FF3D00" d="M6.306,14.691l6.571,4.819C14.655,15.108,18.961,12,24,12c3.059,0,5.842,1.154,7.961,3.039 l5.657-5.657C34.046,6.053,29.268,4,24,4C16.318,4,9.656,8.337,6.306,14.691z"/>
    <path fill="#4CAF50" d="M24,44c5.166,0,9.86-1.977,13.409-5.192l-6.19-5.238C29.211,35.091,26.715,36,24,36 c-5.202,0-9.619-3.317-11.283-7.946l-6.522,5.025C9.505,39.556,16.227,44,24,44z"/>
    <path fill="#1976D2" d="M43.611,20.083H42V20H24v8h11.303c-0.792,2.237-2.231,4.166-4.087,5.571 c0.001-0.001,0.002-0.001,0.003-0.002l6.19,5.238C36.971,39.205,44,34,44,24C44,22.659,43.862,21.35,43.611,20.083z"/>
  </svg>
);

function Login({ t, dark, setDark, onSignIn, authStatus, authError }) {
  const busy = authStatus === "signing-in";
  const [firebaseReady, setFirebaseReady] = useState(() => !!window.__musorichoSignIn);

  useEffect(() => {
    if (window.__musorichoSignIn) { setFirebaseReady(true); return; }
    const handler = () => setFirebaseReady(true);
    window.addEventListener("musoricho-firebase-ready", handler, { once: true });
    return () => window.removeEventListener("musoricho-firebase-ready", handler);
  }, []);

  const disabled = busy || !firebaseReady;

  return (
    <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", background: `linear-gradient(135deg, ${palette.wineDeep}, ${palette.wine} 60%, ${palette.wineLight})`, fontFamily: "-apple-system, Inter, Segoe UI, sans-serif", position: "relative", padding: "24px 12px" }}>
      <button onClick={() => setDark(d => !d)} style={{ position: "absolute", top: 20, right: 20, width: 36, height: 36, borderRadius: 8, border: "1px solid #ffffff40", background: "#ffffff15", color: "#fff", cursor: "pointer" }}>
        {dark ? <Sun size={16} /> : <Moon size={16} />}
      </button>
      <div style={{ width: 380, maxWidth: "100%", background: t.surface, borderRadius: 16, padding: "34px 30px", boxShadow: "0 30px 70px #00000055" }}>
        <div style={{ display: "flex", flexDirection: "column", alignItems: "center", marginBottom: 28 }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "center", marginBottom: 14, height: 64 }}>
            <img src={LOGO_DATA_URI} alt="MUSORICHO logo" style={{ maxHeight: "100%", width: "auto", objectFit: "contain", display: "block" }} />
          </div>
          <div className="serif" style={{ fontSize: 21, fontWeight: 700, color: t.text }}>MUSORICHO</div>
          <div style={{ fontSize: 11, letterSpacing: 2, color: palette.wineLight, fontWeight: 600 }}>WINES &amp; SPIRITS · POS</div>
        </div>

        <div style={{ fontSize: 12.5, color: t.sub, textAlign: "center", marginBottom: 22, lineHeight: 1.5 }}>
          Sign in with your Google account. Your access level (Administrator, Manager, or Cashier) is assigned by your administrator.
        </div>

        {!firebaseReady && (
          <div style={{ display: "flex", alignItems: "center", gap: 8, justifyContent: "center", marginBottom: 16, fontSize: 12, color: t.sub }}>
            <span style={{ width: 8, height: 8, borderRadius: 99, background: palette.gold }} />
            Connecting… (this can take longer on a slow connection)
          </div>
        )}

        <button onClick={onSignIn} disabled={disabled}
          style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "center", gap: 10, padding: "12px", borderRadius: 8, border: `1px solid ${t.border}`, background: t.surface, color: t.text, fontWeight: 700, fontSize: 14, cursor: disabled ? "default" : "pointer", opacity: disabled ? 0.6 : 1 }}>
          <GoogleIcon size={18} />
          {busy ? "Signing in…" : !firebaseReady ? "Please wait…" : "Sign in with Google"}
        </button>

        {authStatus === "denied" && (
          <div style={{ marginTop: 16, padding: 12, borderRadius: 8, border: `1px solid ${palette.danger}`, background: `${palette.danger}12` }}>
            <div style={{ fontSize: 12.5, fontWeight: 700, color: palette.danger, marginBottom: 4 }}>This Google account isn't registered</div>
            <div style={{ fontSize: 11.5, color: t.sub }}>{authError || "Ask your administrator to add your Google account under Settings → Staff Accounts, then try signing in again."}</div>
          </div>
        )}
        {authStatus === "error" && (
          <div style={{ marginTop: 16, padding: 12, borderRadius: 8, border: `1px solid ${palette.danger}`, background: `${palette.danger}12`, fontSize: 11.5, color: palette.danger }}>
            {authError || "Something went wrong signing in. Please try again."}
          </div>
        )}

        <div style={{ textAlign: "center", marginTop: 20, fontSize: 11, color: t.sub, lineHeight: 1.5 }}>
          First time setting this up? The very first person to sign in automatically becomes Administrator.
        </div>
      </div>
    </div>
  );
}

/* ---------------------------------- dashboard ---------------------------------- */
function Dashboard({ t, products, lowStock, outStock, customers, transactions, sales, expenses, setReceipt }) {
  const now = new Date();
  const isSameDay = (d1, d2) => d1.getFullYear() === d2.getFullYear() && d1.getMonth() === d2.getMonth() && d1.getDate() === d2.getDate();
  const startOfWeek = new Date(now); startOfWeek.setDate(now.getDate() - now.getDay()); startOfWeek.setHours(0, 0, 0, 0);
  const [expandedDay, setExpandedDay] = useState(null); // key of the currently expanded day, or null

  const stats = useMemo(() => {
    const profitOf = (sale) => {
      const cogs = sale.items.reduce((a, it) => {
        const prod = products.find(p => p.id === it.id);
        return a + it.qty * (prod ? prod.buy : 0);
      }, 0);
      return (sale.subtotal - sale.discountAmt) - cogs;
    };

    let todaySales = 0, todayProfit = 0, weekSales = 0, monthSales = 0, annualSales = 0, monthProfit = 0, annualProfit = 0;
    const dayBuckets = [0, 0, 0, 0, 0, 0, 0]; // Sun..Sat, sales
    const profitBuckets = [0, 0, 0, 0, 0, 0, 0]; // gross margin, before expenses
    const categoryTotals = {};

    sales.forEach(s => {
      const d = saleTimestamp(s);
      const profit = profitOf(s);
      if (isSameDay(d, now)) { todaySales += s.total; todayProfit += profit; }
      if (d >= startOfWeek) { weekSales += s.total; dayBuckets[d.getDay()] += s.total; profitBuckets[d.getDay()] += profit; }
      if (d.getFullYear() === now.getFullYear() && d.getMonth() === now.getMonth()) { monthSales += s.total; monthProfit += profit; }
      if (d.getFullYear() === now.getFullYear()) { annualSales += s.total; annualProfit += profit; }
      s.items.forEach(it => {
        const prod = products.find(p => p.id === it.id);
        const cat = prod ? prod.category : "Other";
        categoryTotals[cat] = (categoryTotals[cat] || 0) + it.qty * it.price;
      });
    });

    // expenses (rent, transport, etc.) — subtracted from gross margin to get real/net profit
    let todayExpense = 0, monthExpense = 0, annualExpense = 0, totalExpense = 0;
    const expenseDayBuckets = [0, 0, 0, 0, 0, 0, 0];
    const expenseDailyMap = {};
    (expenses || []).forEach(x => {
      const d = new Date(x.date);
      totalExpense += x.amount;
      if (isSameDay(d, now)) todayExpense += x.amount;
      if (d >= startOfWeek) expenseDayBuckets[d.getDay()] += x.amount;
      if (d.getFullYear() === now.getFullYear() && d.getMonth() === now.getMonth()) monthExpense += x.amount;
      if (d.getFullYear() === now.getFullYear()) annualExpense += x.amount;
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
      expenseDailyMap[key] = (expenseDailyMap[key] || 0) + x.amount;
    });

    todayProfit -= todayExpense;
    monthProfit -= monthExpense;
    annualProfit -= annualExpense;

    const dayLabels = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
    const weekChart = dayLabels.map((day, i) => ({ day, sales: dayBuckets[i], profit: profitBuckets[i] - expenseDayBuckets[i] }));

    // day-by-day totals across ALL recorded sales (not just this week), most recent day first
    const dailyMap = {};
    sales.forEach(s => {
      const d = saleTimestamp(s);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
      if (!dailyMap[key]) dailyMap[key] = { key, date: d, sales: 0, profit: 0, count: 0, items: [] };
      dailyMap[key].sales += s.total;
      dailyMap[key].profit += profitOf(s);
      dailyMap[key].count += 1;
      dailyMap[key].items.push(s);
    });
    const dailyTotals = Object.values(dailyMap)
      .sort((a, b) => b.date - a.date)
      .map(d => ({ ...d, profit: d.profit - (expenseDailyMap[d.key] || 0), items: d.items.sort((a, b) => saleTimestamp(b) - saleTimestamp(a)) }));

    const catColors = [palette.wine, palette.gold, palette.wineLight, palette.goldSoft, "#9C8AA5", "#6B8E7C"];
    const categoryPie = Object.entries(categoryTotals).map(([name, value], i) => ({ name, value, color: catColors[i % catColors.length] }));

    return { todaySales, todayProfit, weekSales, monthSales, annualSales, monthProfit, annualProfit, weekChart, categoryPie, dailyTotals, todayExpense, monthExpense, annualExpense, totalExpense };
  }, [sales, products, expenses]);

  const cards = [
    { label: "Today's Sales", value: fmtKES(stats.todaySales), icon: DollarSign, tone: palette.wine },
    { label: "Weekly Sales", value: fmtKES(stats.weekSales), icon: TrendingUp, tone: palette.wineLight },
    { label: "Monthly Sales", value: fmtKES(stats.monthSales), icon: TrendingUp, tone: palette.wine },
    { label: "Annual Sales", value: fmtKES(stats.annualSales), icon: TrendingUp, tone: palette.wineLight },
    { label: "Today's Profit", value: fmtKES(stats.todayProfit), icon: DollarSign, tone: palette.success },
    { label: "Monthly Profit", value: fmtKES(stats.monthProfit), icon: DollarSign, tone: palette.success },
    { label: "Annual Profit", value: fmtKES(stats.annualProfit), icon: DollarSign, tone: palette.success },
    { label: "Monthly Expenses", value: fmtKES(stats.monthExpense), icon: Receipt, tone: palette.danger },
    { label: "Total Products", value: products.length, icon: Package, tone: palette.gold },
    { label: "Low Stock", value: lowStock.length, icon: AlertTriangle, tone: "#C97C22" },
    { label: "Out of Stock", value: outStock.length, icon: AlertTriangle, tone: palette.danger },
    { label: "Total Customers", value: customers.length, icon: Users, tone: palette.wineLight },
  ];

  return (
    <div>
      <div className="card-grid" style={{ marginBottom: 24 }}>
        {cards.map(c => (
          <div key={c.label} style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 16 }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 10 }}>
              <span style={{ fontSize: 11.5, color: t.sub, fontWeight: 600 }}>{c.label}</span>
              <c.icon size={15} color={c.tone} />
            </div>
            <div className="serif" style={{ fontSize: 19, fontWeight: 700 }}>{c.value}</div>
          </div>
        ))}
      </div>

      <div className="two-col-wide" style={{ marginBottom: 16 }}>
        <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 18 }}>
          <div className="serif" style={{ fontWeight: 700, marginBottom: 12, fontSize: 14.5 }}>This Week's Sales &amp; Profit</div>
          <ResponsiveContainer width="100%" height={230}>
            <LineChart data={stats.weekChart}>
              <CartesianGrid strokeDasharray="3 3" stroke={t.border} />
              <XAxis dataKey="day" stroke={t.sub} fontSize={11} />
              <YAxis stroke={t.sub} fontSize={11} tickFormatter={(v) => `${v / 1000}k`} />
              <Tooltip formatter={(v) => fmtKES(v)} contentStyle={{ background: t.surface, border: `1px solid ${t.border}`, fontSize: 12 }} />
              <Legend wrapperStyle={{ fontSize: 12 }} />
              <Line type="monotone" dataKey="sales" stroke={palette.wine} strokeWidth={2.5} dot={{ r: 3 }} name="Sales" />
              <Line type="monotone" dataKey="profit" stroke={palette.gold} strokeWidth={2.5} dot={{ r: 3 }} name="Profit" />
            </LineChart>
          </ResponsiveContainer>
        </div>
        <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 18 }}>
          <div className="serif" style={{ fontWeight: 700, marginBottom: 12, fontSize: 14.5 }}>Sales by Category</div>
          {stats.categoryPie.length > 0 ? (
            <ResponsiveContainer width="100%" height={230}>
              <PieChart>
                <Pie data={stats.categoryPie} dataKey="value" nameKey="name" innerRadius={45} outerRadius={80} paddingAngle={2}>
                  {stats.categoryPie.map((c, i) => <Cell key={i} fill={c.color} />)}
                </Pie>
                <Tooltip formatter={(v) => fmtKES(v)} contentStyle={{ background: t.surface, border: `1px solid ${t.border}`, fontSize: 12 }} />
                <Legend wrapperStyle={{ fontSize: 11 }} />
              </PieChart>
            </ResponsiveContainer>
          ) : (
            <div style={{ height: 230, display: "flex", alignItems: "center", justifyContent: "center", color: t.sub, fontSize: 12.5 }}>No sales yet</div>
          )}
        </div>
      </div>

      <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 18, marginBottom: 16 }}>
        <div className="serif" style={{ fontWeight: 700, marginBottom: 4, fontSize: 14.5 }}>Daily Sales</div>
        <div style={{ fontSize: 11.5, color: t.sub, marginBottom: 10 }}>Tap a date to expand it and see the individual sales made that day.</div>
        {stats.dailyTotals.length === 0 ? (
          <div style={{ color: t.sub, fontSize: 12.5 }}>No sales recorded yet.</div>
        ) : (
          <div style={{ maxHeight: 340, overflowY: "auto" }}>
            {stats.dailyTotals.map(d => {
              const isOpen = expandedDay === d.key;
              return (
                <div key={d.key} style={{ borderBottom: `1px solid ${t.border}` }}>
                  <button onClick={() => setExpandedDay(isOpen ? null : d.key)}
                    style={{ display: "flex", justifyContent: "space-between", alignItems: "center", width: "100%", padding: "9px 2px", fontSize: 12.5, background: "none", border: "none", textAlign: "left", cursor: "pointer", color: t.text }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                      <span style={{ display: "inline-block", transition: "transform 0.15s", transform: isOpen ? "rotate(90deg)" : "rotate(0deg)", color: t.sub, fontSize: 12 }}>›</span>
                      <div>
                        <div style={{ fontWeight: 600 }}>{d.date.toLocaleDateString(undefined, { weekday: "short", day: "numeric", month: "short", year: "numeric" })}</div>
                        <div style={{ color: t.sub, fontSize: 11 }}>{d.count} sale{d.count === 1 ? "" : "s"} · Profit {fmtKES(d.profit)}</div>
                      </div>
                    </div>
                    <div style={{ fontWeight: 700, color: palette.wine }}>{fmtKES(d.sales)}</div>
                  </button>
                  {isOpen && (
                    <div style={{ padding: "0 2px 10px 20px" }}>
                      {d.items.map(s => (
                        <button key={s.id} onClick={() => setReceipt(s)}
                          style={{ display: "flex", justifyContent: "space-between", alignItems: "center", width: "100%", padding: "7px 0", background: "none", border: "none", borderTop: `1px dashed ${t.border}`, textAlign: "left", cursor: "pointer", color: t.text }}>
                          <div>
                            <div style={{ fontWeight: 600, fontSize: 12 }}>{s.id}</div>
                            <div style={{ color: t.sub, fontSize: 10.5 }}>{s.time} · {s.cashier} · {s.method}</div>
                          </div>
                          <span style={{ fontWeight: 700, fontSize: 12, color: palette.wine }}>{fmtKES(s.total)}</span>
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>

      <div className="two-col">
        <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 18 }}>
          <div className="serif" style={{ fontWeight: 700, marginBottom: 12, fontSize: 14.5 }}>Recent Transactions</div>
          {transactions.slice(0, 5).map(tx => {
            const fullSale = sales.find(s => s.id === tx.id);
            return (
              <button key={tx.id} onClick={() => fullSale && setReceipt(fullSale)}
                style={{ display: "flex", justifyContent: "space-between", alignItems: "center", width: "100%", padding: "8px 0", borderBottom: `1px solid ${t.border}`, fontSize: 12.5,
                  background: "none", border: "none", borderBottomWidth: 1, borderBottomStyle: "solid", borderBottomColor: t.border, textAlign: "left", cursor: fullSale ? "pointer" : "default", color: t.text }}>
                <div>
                  <div style={{ fontWeight: 600 }}>{tx.id}</div>
                  <div style={{ color: t.sub, fontSize: 11 }}>{tx.cashier} · {tx.time} · {tx.method}</div>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <div style={{ fontWeight: 700, color: palette.wine }}>{fmtKES(tx.total)}</div>
                  {fullSale && <Eye size={14} color={t.sub} />}
                </div>
              </button>
            );
          })}
          {transactions.length === 0 && <div style={{ color: t.sub, fontSize: 12.5 }}>No transactions yet.</div>}
        </div>
        <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 18 }}>
          <div className="serif" style={{ fontWeight: 700, marginBottom: 12, fontSize: 14.5 }}>Stock Alerts</div>
          {[...outStock.map(p => ({ ...p, tag: "OUT OF STOCK", tone: palette.danger })), ...lowStock.map(p => ({ ...p, tag: "LOW STOCK", tone: "#C97C22" }))]
            .slice(0, 6).map(p => (
              <div key={p.id} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "8px 0", borderBottom: `1px solid ${t.border}`, fontSize: 12.5 }}>
                <span>{p.name}</span>
                <span style={{ fontSize: 10, fontWeight: 700, color: p.tone, background: `${p.tone}18`, padding: "2px 8px", borderRadius: 20 }}>{p.tag} · {p.qty}</span>
              </div>
            ))}
          {outStock.length + lowStock.length === 0 && <div style={{ color: t.sub, fontSize: 12.5 }}>All stock levels healthy.</div>}
        </div>
      </div>
    </div>
  );
}

/* ---------------------------------- POS / sales ---------------------------------- */
function POS({ t, products, setProducts, categories, role, cart, setCart, discountPct, setDiscountPct, payMethod, setPayMethod, customerId, setCustomerId, customers, cashierName, businessInfo, onComplete }) {
  const [query, setQuery] = useState("");
  const [cat, setCat] = useState("All");
  const [editingId, setEditingId] = useState(null);
  const [editPriceValue, setEditPriceValue] = useState("");
  const vatRate = (businessInfo.vatRate ?? 16) / 100;
  const canEditPrice = true; // price editing enabled for all roles

  const filtered = products.filter(p =>
    (cat === "All" || p.category === cat) &&
    (p.name.toLowerCase().includes(query.toLowerCase()) || (p.sku || "").toLowerCase().includes(query.toLowerCase()))
  );

  const addToCart = (p) => {
    if (p.qty <= 0) return;
    setCart(c => {
      const existing = c.find(i => i.id === p.id);
      if (existing) {
        if (existing.qty >= p.qty) return c;
        return c.map(i => i.id === p.id ? { ...i, qty: i.qty + 1 } : i);
      }
      return [...c, { id: p.id, name: p.name, category: p.category, price: p.sell, origPrice: p.sell, qty: 1, max: p.qty }];
    });
  };
  const changeQty = (id, delta) => setCart(c => c.map(i => i.id === id ? { ...i, qty: Math.max(1, Math.min(i.max, i.qty + delta)) } : i));
  const removeItem = (id) => setCart(c => c.filter(i => i.id !== id));

  const startEditPrice = (item) => { setEditingId(item.id); setEditPriceValue(String(item.price)); };
  const cancelEditPrice = () => { setEditingId(null); setEditPriceValue(""); };
  const confirmEditPrice = (id) => {
    const val = Number(editPriceValue);
    if (isNaN(val) || val < 0) { setEditingId(null); setEditPriceValue(""); return; }
    setCart(c => c.map(i => i.id === id ? { ...i, price: val } : i));
    setEditingId(null); setEditPriceValue("");
  };

  const subtotal = cart.reduce((a, i) => a + i.price * i.qty, 0);
  const discountAmt = Math.round(subtotal * (discountPct / 100));
  const taxable = subtotal - discountAmt;
  const vat = Math.round(taxable * vatRate);
  const total = taxable + vat;

  const completeSale = () => {
    if (cart.length === 0) return;
    setProducts(list => list.map(p => {
      const item = cart.find(i => i.id === p.id);
      return item ? { ...p, qty: p.qty - item.qty } : p;
    }));
    const sale = {
      id: "RC-" + Math.floor(10000 + Math.random() * 89999),
      ts: Date.now(),
      time: new Date().toLocaleTimeString("en-KE", { hour: "2-digit", minute: "2-digit" }),
      date: new Date().toLocaleDateString("en-KE"),
      cashier: cashierName,
      customer: customers.find(c => c.id === customerId)?.name || "Walk-in Customer",
      items: cart, subtotal, discountAmt, vat, vatPct: businessInfo.vatRate ?? 16, total, method: payMethod,
    };
    onComplete(sale);
  };

  return (
    <div className="pos-grid">
      {/* product picker */}
      <div style={{ display: "flex", flexDirection: "column", minHeight: 0 }}>
        <div style={{ display: "flex", gap: 8, marginBottom: 12 }}>
          <div style={{ flex: 1, display: "flex", alignItems: "center", gap: 8, background: t.surface, border: `1px solid ${t.border}`, borderRadius: 10, padding: "9px 12px" }}>
            <Search size={15} color={t.sub} />
            <input value={query} onChange={e => setQuery(e.target.value)} placeholder="Search by name, SKU, or scan barcode..."
              style={{ border: "none", outline: "none", background: "transparent", color: t.text, fontSize: 13.5, width: "100%" }} />
          </div>
        </div>
        <div style={{ display: "flex", gap: 6, marginBottom: 12, flexWrap: "wrap" }}>
          {categories.map(c => (
            <button key={c} onClick={() => setCat(c)}
              style={{ padding: "6px 14px", borderRadius: 20, fontSize: 12, fontWeight: 600, cursor: "pointer",
                border: `1px solid ${cat === c ? palette.wine : t.border}`, background: cat === c ? palette.wine : "transparent", color: cat === c ? "#fff" : t.text }}>
              {c}
            </button>
          ))}
        </div>
        <div className="pos-products" style={{ overflowY: "auto", alignContent: "start", paddingRight: 4 }}>
          {filtered.map(p => (
            <button key={p.id} onClick={() => addToCart(p)} disabled={p.qty <= 0}
              style={{ textAlign: "left", background: t.surface, border: `1px solid ${t.border}`, borderRadius: 10, padding: 12, cursor: p.qty > 0 ? "pointer" : "not-allowed", opacity: p.qty > 0 ? 1 : 0.45 }}>
              <div style={{ width: "100%", height: 54, borderRadius: 6, background: `linear-gradient(135deg, ${palette.wine}22, ${palette.gold}22)`, display: "flex", alignItems: "center", justifyContent: "center", marginBottom: 8 }}>
                <Wine size={22} color={palette.wine} />
              </div>
              <div style={{ fontSize: 12, fontWeight: 600, lineHeight: 1.3, marginBottom: 4 }}>{p.name}</div>
              <div style={{ fontSize: 11, color: t.sub, marginBottom: 4 }}>{p.qty} in stock</div>
              <div style={{ fontSize: 13, fontWeight: 700, color: palette.wine }}>{fmtKES(p.sell)}</div>
            </button>
          ))}
        </div>
      </div>

      {/* cart */}
      <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, display: "flex", flexDirection: "column", minHeight: 0 }}>
        <div style={{ padding: 14, borderBottom: `1px solid ${t.border}` }}>
          <div className="serif" style={{ fontWeight: 700, fontSize: 15, marginBottom: 8 }}>Current Sale</div>
          <select value={customerId} onChange={e => setCustomerId(Number(e.target.value))}
            style={{ width: "100%", padding: "7px 8px", borderRadius: 8, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontSize: 12.5 }}>
            {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
          </select>
        </div>
        <div style={{ flex: 1, overflowY: "auto", padding: 14 }}>
          {cart.length === 0 && <div style={{ color: t.sub, fontSize: 12.5, textAlign: "center", marginTop: 30 }}>Cart is empty — tap a product to add it.</div>}
          {cart.map(i => {
            const editing = editingId === i.id;
            const wasOverridden = i.origPrice !== undefined && i.price !== i.origPrice;
            return (
              <div key={i.id} style={{ marginBottom: 12, paddingBottom: 12, borderBottom: `1px solid ${t.border}` }}>
                <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12.5, fontWeight: 600, marginBottom: 6 }}>
                  <span>{i.name}</span>
                  <button onClick={() => removeItem(i.id)} style={{ background: "none", border: "none", color: palette.danger, cursor: "pointer" }}><Trash2 size={13} /></button>
                </div>
                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", flexWrap: "wrap", gap: 6 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <button onClick={() => changeQty(i.id, -1)} style={{ width: 22, height: 22, borderRadius: 6, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer" }}><Minus size={11} /></button>
                    <span style={{ fontSize: 12.5, fontWeight: 700, width: 18, textAlign: "center" }}>{i.qty}</span>
                    <button onClick={() => changeQty(i.id, 1)} style={{ width: 22, height: 22, borderRadius: 6, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer" }}><Plus size={11} /></button>
                  </div>

                  {editing ? (
                    <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
                      <span style={{ fontSize: 11, color: t.sub }}>{businessInfo.currency || "KES"}</span>
                      <input type="number" autoFocus value={editPriceValue} onChange={e => setEditPriceValue(e.target.value)}
                        onKeyDown={e => { if (e.key === "Enter") confirmEditPrice(i.id); if (e.key === "Escape") cancelEditPrice(); }}
                        style={{ width: 72, padding: "4px 6px", borderRadius: 6, border: `1px solid ${palette.wine}`, background: "transparent", color: t.text, fontSize: 12.5 }} />
                      <button onClick={() => confirmEditPrice(i.id)} title="Confirm price" style={{ background: "none", border: "none", color: palette.success, cursor: "pointer", padding: 2 }}><Check size={14} /></button>
                      <button onClick={cancelEditPrice} title="Cancel" style={{ background: "none", border: "none", color: t.sub, cursor: "pointer", padding: 2 }}><X size={14} /></button>
                    </div>
                  ) : (
                    <div style={{ display: "flex", alignItems: "center", gap: 6, WebkitUserSelect: "none", userSelect: "none" }}>
                      <span style={{ fontSize: 12.5, fontWeight: 700 }}>{fmtKES(i.price * i.qty)}</span>
                      {canEditPrice && (
                        <button onClick={() => startEditPrice(i)} title="Edit unit price" style={{ background: "none", border: "none", color: t.sub, cursor: "pointer", padding: 2 }}><Pencil size={12} /></button>
                      )}
                    </div>
                  )}
                </div>
                {wasOverridden && !editing && (
                  <div style={{ fontSize: 10, color: palette.gold, marginTop: 4, textAlign: "right" }}>
                    Price adjusted from {fmtKES(i.origPrice)}
                  </div>
                )}
              </div>
            );
          })}
        </div>
        <div style={{ padding: 14, borderTop: `1px solid ${t.border}` }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}>
            <span style={{ fontSize: 12, color: t.sub }}>Discount %</span>
            <input type="number" min={0} max={100} value={discountPct} onChange={e => setDiscountPct(Math.max(0, Math.min(100, Number(e.target.value))))}
              style={{ width: 56, padding: "5px 7px", borderRadius: 6, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontSize: 12 }} />
          </div>
          <Row label="Subtotal" value={fmtKES(subtotal)} t={t} />
          <Row label="Discount" value={`-${fmtKES(discountAmt)}`} t={t} />
          <Row label={`VAT (${businessInfo.vatRate ?? 16}%)`} value={fmtKES(vat)} t={t} />
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 16, fontWeight: 800, margin: "8px 0 12px" }}>
            <span>Total</span><span style={{ color: palette.wine }}>{fmtKES(total)}</span>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6, marginBottom: 10 }}>
            {["Cash", "M-Pesa", "Card", "Bank Transfer"].map(m => (
              <button key={m} onClick={() => setPayMethod(m)} style={{ padding: "7px 4px", borderRadius: 7, fontSize: 11.5, fontWeight: 600, cursor: "pointer",
                border: `1px solid ${payMethod === m ? palette.wine : t.border}`, background: payMethod === m ? palette.wine : "transparent", color: payMethod === m ? "#fff" : t.text }}>
                {m}
              </button>
            ))}
          </div>
          <button onClick={completeSale} disabled={cart.length === 0}
            style={{ width: "100%", padding: 12, borderRadius: 9, border: "none", background: cart.length ? palette.wine : `${palette.wine}55`, color: "#fff", fontWeight: 700, fontSize: 14, cursor: cart.length ? "pointer" : "not-allowed" }}>
            Complete Sale
          </button>
        </div>
      </div>
    </div>
  );
}
function Row({ label, value, t }) {
  return <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12.5, color: t.sub, marginBottom: 4 }}><span>{label}</span><span>{value}</span></div>;
}

/* ---------------------------------- receipt ---------------------------------- */
function ReceiptModal({ t, sale, businessInfo, printer, printViaBluetooth, onClose }) {
  useEffect(() => {
    const handleAfterPrint = () => onClose();
    window.addEventListener("afterprint", handleAfterPrint);
    return () => window.removeEventListener("afterprint", handleAfterPrint);
  }, [onClose]);

  const handleBluetoothPrint = async () => {
    await printViaBluetooth(sale);
    onClose();
  };

  return (
    <div style={{ position: "fixed", inset: 0, background: "#00000088", display: "flex", alignItems: "flex-start", justifyContent: "center", zIndex: 100, overflowY: "auto", padding: "32px 12px" }}>
      <style>{`
        @media print {
          body * { visibility: hidden; }
          .receipt-print, .receipt-print * { visibility: visible; }
          .receipt-print { position: absolute; top: 0; left: 0; width: 58mm !important; box-shadow: none !important; border-radius: 0 !important; }
          .receipt-print > div { padding-left: 6px !important; padding-right: 6px !important; }
          .no-print { display: none !important; }
          @page { margin: 0; size: 58mm auto; }
        }
      `}</style>
      <div className="receipt-print" style={{ width: 300, flexShrink: 0, background: "#fff", color: "#222", borderRadius: 4, position: "relative", fontFamily: "'Courier New', monospace" }}>
        <button onClick={onClose} className="no-print" style={{ position: "absolute", top: -12, right: -12, width: 28, height: 28, borderRadius: "50%", background: palette.wine, color: "#fff", border: "3px solid #fff", cursor: "pointer" }}><X size={13} /></button>
        <div style={{ padding: "20px 18px 14px", borderBottom: "1px dashed #999" }}>
          <div style={{ display: "flex", justifyContent: "center", marginBottom: 8 }}>
            <img src={LOGO_DATA_URI} alt="" style={{ maxHeight: 46, width: "auto", display: "block" }} />
          </div>
          <div style={{ textAlign: "center", fontWeight: 700, fontSize: 14 }}>{businessInfo.name}</div>
          <div style={{ textAlign: "center", fontSize: 10, color: "#555" }}>{businessInfo.address} · {businessInfo.phone}</div>
          <div style={{ textAlign: "center", fontSize: 10, color: "#555" }}>Till: {businessInfo.till}</div>
        </div>
        <div style={{ padding: "12px 18px", fontSize: 10.5, borderBottom: "1px dashed #999" }}>
          <div style={{ display: "flex", justifyContent: "space-between" }}><span>Receipt#</span><span>{sale.id}</span></div>
          <div style={{ display: "flex", justifyContent: "space-between" }}><span>Date</span><span>{sale.date} {sale.time}</span></div>
          <div style={{ display: "flex", justifyContent: "space-between" }}><span>Cashier</span><span>{sale.cashier}</span></div>
          <div style={{ display: "flex", justifyContent: "space-between" }}><span>Customer</span><span>{sale.customer}</span></div>
        </div>
        <div style={{ padding: "12px 18px", borderBottom: "1px dashed #999" }}>
          {sale.items.map(i => (
            <div key={i.id} style={{ fontSize: 10.5, marginBottom: 6 }}>
              <div>{i.name}</div>
              {i.category && <div style={{ color: "#888", fontSize: 9.5 }}>{i.category}</div>}
              <div style={{ display: "flex", justifyContent: "space-between", color: "#555" }}>
                <span>{i.qty} x {fmtKES(i.price)}</span><span>{fmtKES(i.qty * i.price)}</span>
              </div>
            </div>
          ))}
        </div>
        <div style={{ padding: "12px 18px", fontSize: 10.5, borderBottom: "1px dashed #999" }}>
          <div style={{ display: "flex", justifyContent: "space-between" }}><span>Subtotal</span><span>{fmtKES(sale.subtotal)}</span></div>
          <div style={{ display: "flex", justifyContent: "space-between" }}><span>Discount</span><span>-{fmtKES(sale.discountAmt)}</span></div>
          <div style={{ display: "flex", justifyContent: "space-between" }}><span>VAT ({sale.vatPct ?? 16}%)</span><span>{fmtKES(sale.vat)}</span></div>
          <div style={{ display: "flex", justifyContent: "space-between", fontWeight: 700, fontSize: 12, marginTop: 4 }}><span>TOTAL</span><span>{fmtKES(sale.total)}</span></div>
          <div style={{ display: "flex", justifyContent: "space-between", marginTop: 4 }}><span>Paid via</span><span>{sale.method}</span></div>
        </div>
        <div style={{ padding: "14px 18px 20px", textAlign: "center" }}>
          <div style={{ fontSize: 10.5, marginBottom: 8 }}>Thank You for Shopping With Us</div>
          <div style={{ fontSize: 9, color: "#777", marginBottom: 14 }}>Drink responsibly · Goods sold are not returnable</div>
          <div className="no-print" style={{ display: "flex", gap: 8, marginBottom: 8 }}>
            <button onClick={() => window.print()} style={{ flex: 1, padding: 9, borderRadius: 6, border: "none", background: palette.wine, color: "#fff", fontWeight: 700, fontSize: 12, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}>
              <Printer size={13} /> Print
            </button>
            <button onClick={handleBluetoothPrint} style={{ flex: 1, padding: 9, borderRadius: 6, border: `1px solid ${palette.wine}`, background: "transparent", color: palette.wine, fontWeight: 700, fontSize: 12, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}>
              <Bluetooth size={13} /> {printer ? "Print" : "Connect & Print"}
            </button>
          </div>
          <button onClick={onClose} className="no-print" style={{ width: "100%", padding: 9, borderRadius: 6, border: `1px solid ${t.border}`, background: "transparent", color: "#666", fontWeight: 600, fontSize: 12, cursor: "pointer" }}>
            New Sale
          </button>
        </div>
      </div>
    </div>
  );
}

/* ---------------------------------- products ---------------------------------- */
function Products({ t, products, setProducts, categories, setCategories, onEdit, onAdd, showToast, role }) {
  const [query, setQuery] = useState("");
  const [cat, setCat] = useState("All");
  const [newCat, setNewCat] = useState("");
  const filtered = products.filter(p => (cat === "All" || p.category === cat) && p.name.toLowerCase().includes(query.toLowerCase()));

  const addCategory = () => {
    const name = newCat.trim();
    if (!name) return;
    if (categories.some(c => c.toLowerCase() === name.toLowerCase())) {
      showToast("That category already exists");
      return;
    }
    setCategories(list => [...list, name]);
    setNewCat("");
    showToast(`Category "${name}" added`);
  };

  return (
    <div>
      <div style={{ display: "flex", gap: 10, marginBottom: 16, flexWrap: "wrap" }}>
        <div style={{ flex: 1, minWidth: 200, display: "flex", alignItems: "center", gap: 8, background: t.surface, border: `1px solid ${t.border}`, borderRadius: 10, padding: "9px 12px" }}>
          <Search size={15} color={t.sub} />
          <input value={query} onChange={e => setQuery(e.target.value)} placeholder="Search products or SKU..." style={{ border: "none", outline: "none", background: "transparent", color: t.text, fontSize: 13, width: "100%" }} />
        </div>
        <select value={cat} onChange={e => setCat(e.target.value)} style={{ padding: "9px 12px", borderRadius: 10, border: `1px solid ${t.border}`, background: t.surface, color: t.text, fontSize: 13 }}>
          {categories.map(c => <option key={c}>{c}</option>)}
        </select>
        <button onClick={onAdd} style={{ display: "flex", alignItems: "center", gap: 6, padding: "9px 16px", borderRadius: 10, border: "none", background: palette.wine, color: "#fff", fontWeight: 600, fontSize: 13, cursor: "pointer" }}>
          <Plus size={15} /> Add Product
        </button>
      </div>

      {role === "Administrator" && (
        <div style={{ display: "flex", gap: 8, alignItems: "center", marginBottom: 16, background: t.surface, border: `1px solid ${t.border}`, borderRadius: 10, padding: "9px 12px" }}>
          <span style={{ fontSize: 12, fontWeight: 600, color: t.sub, whiteSpace: "nowrap" }}>New category</span>
          <input value={newCat} onChange={e => setNewCat(e.target.value)} onKeyDown={e => { if (e.key === "Enter") addCategory(); }}
            placeholder="e.g. Vodka" style={{ flex: 1, border: `1px solid ${t.border}`, outline: "none", background: "transparent", color: t.text, fontSize: 13, borderRadius: 7, padding: "6px 10px", minWidth: 120 }} />
          <button onClick={addCategory} style={{ display: "flex", alignItems: "center", gap: 6, padding: "7px 14px", borderRadius: 8, border: "none", background: palette.wine, color: "#fff", fontWeight: 600, fontSize: 12.5, cursor: "pointer", whiteSpace: "nowrap" }}>
            <Plus size={13} /> Add Category
          </button>
        </div>
      )}

      <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, overflow: "hidden" }}>
        <div className="scroll-hint">Swipe left to see status &amp; actions →</div>
        <div style={{ overflowX: "auto", WebkitOverflowScrolling: "touch" }}>
        <table style={{ width: "100%", minWidth: 760, borderCollapse: "collapse", fontSize: 12.5 }}>
          <thead>
            <tr style={{ background: `${palette.wine}0F`, textAlign: "left" }}>
              {["Product", "SKU", "Category", "Buy Price", "Sell Price", "Qty", "Status", ""].map(h => (
                <th key={h} style={{ padding: "10px 14px", fontWeight: 700, color: t.sub, fontSize: 11, whiteSpace: "nowrap" }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.map(p => {
              const status = p.qty === 0 ? { l: "Out of Stock", c: palette.danger } : p.qty <= p.min ? { l: "Low Stock", c: "#C97C22" } : { l: "In Stock", c: palette.success };
              return (
                <tr key={p.id} style={{ borderTop: `1px solid ${t.border}` }}>
                  <td style={{ padding: "10px 14px", fontWeight: 600, whiteSpace: "nowrap" }}>{p.name}<div style={{ fontSize: 10.5, color: t.sub, fontWeight: 400 }}>{p.brand} · {p.size}</div></td>
                  <td style={{ padding: "10px 14px", color: t.sub, whiteSpace: "nowrap" }}>{p.sku}</td>
                  <td style={{ padding: "10px 14px", whiteSpace: "nowrap" }}>{p.category}</td>
                  <td style={{ padding: "10px 14px", whiteSpace: "nowrap" }}>{fmtKES(p.buy)}</td>
                  <td style={{ padding: "10px 14px", fontWeight: 700, color: palette.wine, whiteSpace: "nowrap" }}>{fmtKES(p.sell)}</td>
                  <td style={{ padding: "10px 14px" }}>{p.qty}</td>
                  <td style={{ padding: "10px 14px" }}><span style={{ fontSize: 10, fontWeight: 700, color: status.c, background: `${status.c}18`, padding: "3px 9px", borderRadius: 20, whiteSpace: "nowrap" }}>{status.l}</span></td>
                  <td style={{ padding: "10px 14px" }}>
                    <div style={{ display: "flex", gap: 6 }}>
                      <button onClick={() => onEdit(p)} style={{ fontSize: 11, padding: "5px 10px", borderRadius: 6, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer", whiteSpace: "nowrap" }}>Edit</button>
                      {role === "Administrator" && (
                        <button onClick={() => { setProducts(list => list.filter(x => x.id !== p.id)); showToast("Product deleted"); }}
                          style={{ fontSize: 11, padding: "5px 8px", borderRadius: 6, border: `1px solid ${palette.danger}55`, background: "transparent", color: palette.danger, cursor: "pointer" }}>
                          <Trash2 size={11} />
                        </button>
                      )}
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        </div>
      </div>
    </div>
  );
}

function ProductModal({ t, mode, data, categories, setCategories, onClose, onSave }) {
  const [form, setForm] = useState(data || { name: "", sku: "", category: categories?.[1] || categories?.[0] || "Whisky", brand: "", size: "750ml", buy: "", sell: "", qty: "", min: "" });
  const [newCat, setNewCat] = useState("");
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));
  const valid = form.name && form.buy !== "" && form.sell !== "";

  const addCategory = () => {
    const name = newCat.trim();
    if (!name) return;
    if (categories.some(c => c.toLowerCase() === name.toLowerCase())) return;
    setCategories(list => [...list, name]);
    set("category", name);
    setNewCat("");
  };
  return (
    <div style={{ position: "fixed", inset: 0, background: "#00000088", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 100 }}>
      <div style={{ width: 460, background: t.surface, color: t.text, borderRadius: 14, padding: 22, maxHeight: "88vh", overflowY: "auto" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <div className="serif" style={{ fontWeight: 700, fontSize: 16 }}>{mode === "add" ? "Add Product" : "Edit Product"}</div>
          <button onClick={onClose} style={{ background: "none", border: "none", color: t.text, cursor: "pointer" }}><X size={18} /></button>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
          <Field t={t} label="Product Name" full value={form.name} onChange={v => set("name", v)} />
          <Field t={t} label="SKU / Barcode (optional)" value={form.sku} onChange={v => set("sku", v)} />
          <SelectField t={t} label="Category" value={form.category} onChange={v => set("category", v)} options={categories.filter(c => c !== "All")} />
          <div style={{ gridColumn: "1 / -1", display: "flex", gap: 8, alignItems: "flex-end" }}>
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: 11, fontWeight: 600, color: t.sub }}>Add a new category</label>
              <input value={newCat} onChange={e => setNewCat(e.target.value)} onKeyDown={e => { if (e.key === "Enter") { e.preventDefault(); addCategory(); } }}
                placeholder="e.g. Vodka" style={{ width: "100%", padding: "8px 10px", marginTop: 4, borderRadius: 7, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontSize: 13 }} />
            </div>
            <button type="button" onClick={addCategory} style={{ padding: "8px 12px", borderRadius: 7, border: "none", background: palette.wine, color: "#fff", fontWeight: 600, fontSize: 12.5, cursor: "pointer" }}>
              Add
            </button>
          </div>
          <Field t={t} label="Brand" value={form.brand} onChange={v => set("brand", v)} />
          <Field t={t} label="Bottle Size" value={form.size} onChange={v => set("size", v)} />
          <Field t={t} label="Buying Price (KES)" type="number" value={form.buy} onChange={v => set("buy", v)} />
          <Field t={t} label="Selling Price (KES)" type="number" value={form.sell} onChange={v => set("sell", v)} />
          <Field t={t} label="Quantity" type="number" value={form.qty} onChange={v => set("qty", v)} />
          <Field t={t} label="Low Stock Threshold" type="number" value={form.min} onChange={v => set("min", v)} />
        </div>
        <button disabled={!valid} onClick={() => onSave({ ...form, id: data?.id, buy: Number(form.buy), sell: Number(form.sell), qty: Number(form.qty) || 0, min: Number(form.min) || 5 })}
          style={{ width: "100%", marginTop: 18, padding: 11, borderRadius: 9, border: "none", background: valid ? palette.wine : `${palette.wine}55`, color: "#fff", fontWeight: 700, fontSize: 13.5, cursor: valid ? "pointer" : "not-allowed" }}>
          Save Product
        </button>
      </div>
    </div>
  );
}
function Field({ t, label, value, onChange, type = "text", full }) {
  return (
    <div style={{ gridColumn: full ? "1 / -1" : "auto" }}>
      <label style={{ fontSize: 11, fontWeight: 600, color: t.sub }}>{label}</label>
      <input type={type} value={value} onChange={e => onChange(e.target.value)}
        style={{ width: "100%", padding: "8px 10px", marginTop: 4, borderRadius: 7, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontSize: 13 }} />
    </div>
  );
}
function SelectField({ t, label, value, onChange, options }) {
  return (
    <div>
      <label style={{ fontSize: 11, fontWeight: 600, color: t.sub }}>{label}</label>
      <select value={value} onChange={e => onChange(e.target.value)}
        style={{ width: "100%", padding: "8px 10px", marginTop: 4, borderRadius: 7, border: `1px solid ${t.border}`, background: t.surface, color: t.text, fontSize: 13 }}>
        {options.map(o => <option key={o}>{o}</option>)}
      </select>
    </div>
  );
}

/* ---------------------------------- inventory ---------------------------------- */
function Inventory({ t, products, setProducts, lowStock, outStock, onStockIn, showToast, role }) {
  const totalValue = products.reduce((a, p) => a + p.buy * p.qty, 0);
  const isAdmin = role === "Administrator";
  const [confirmingReset, setConfirmingReset] = useState(false);
  const [confirmingRowId, setConfirmingRowId] = useState(null);

  return (
    <div>
      <div className="four-col" style={{ marginBottom: 18 }}>
        <MiniStat t={t} label="Inventory Value" value={fmtKES(totalValue)} />
        <MiniStat t={t} label="Total Units" value={products.reduce((a, p) => a + p.qty, 0)} />
        <MiniStat t={t} label="Low Stock Items" value={lowStock.length} tone="#C97C22" />
        <MiniStat t={t} label="Out of Stock" value={outStock.length} tone={palette.danger} />
      </div>

      {isAdmin && (
        <div style={{ display: "flex", justifyContent: "flex-end", marginBottom: 12 }}>
          {!confirmingReset ? (
            <button onClick={() => setConfirmingReset(true)} disabled={products.length === 0}
              style={{ display: "flex", alignItems: "center", gap: 6, padding: "8px 14px", borderRadius: 8, border: `1px solid ${palette.danger}55`, background: "transparent", color: products.length ? palette.danger : t.sub, fontWeight: 600, fontSize: 12, cursor: products.length ? "pointer" : "not-allowed" }}>
              <Trash2 size={13} /> Reset Inventory
            </button>
          ) : (
            <div style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 12, color: t.sub }}>
              <span>Delete all {products.length} products?</span>
              <button onClick={() => setConfirmingReset(false)} style={{ padding: "7px 12px", borderRadius: 7, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer", fontSize: 12 }}>Cancel</button>
              <button onClick={() => { setProducts([]); setConfirmingReset(false); showToast("Inventory reset"); }} style={{ padding: "7px 12px", borderRadius: 7, border: "none", background: palette.danger, color: "#fff", fontWeight: 700, cursor: "pointer", fontSize: 12 }}>Confirm Reset</button>
            </div>
          )}
        </div>
      )}

      <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, overflow: "hidden" }}>
        <div className="scroll-hint">Swipe left to see status &amp; actions →</div>
        <div style={{ overflowX: "auto", WebkitOverflowScrolling: "touch" }}>
        <table style={{ width: "100%", minWidth: 640, borderCollapse: "collapse", fontSize: 12.5 }}>
          <thead>
            <tr style={{ background: `${palette.wine}0F`, textAlign: "left" }}>
              {["Product", "Current Stock", "Threshold", "Stock Value", "Status", ""].map(h => <th key={h} style={{ padding: "10px 14px", fontWeight: 700, color: t.sub, fontSize: 11, whiteSpace: "nowrap" }}>{h}</th>)}
            </tr>
          </thead>
          <tbody>
            {products.map(p => {
              const status = p.qty === 0 ? { l: "Out of Stock", c: palette.danger } : p.qty <= p.min ? { l: "Low Stock", c: "#C97C22" } : { l: "Healthy", c: palette.success };
              return (
                <tr key={p.id} style={{ borderTop: `1px solid ${t.border}` }}>
                  <td style={{ padding: "10px 14px", fontWeight: 600, whiteSpace: "nowrap" }}>{p.name}</td>
                  <td style={{ padding: "10px 14px" }}>{p.qty}</td>
                  <td style={{ padding: "10px 14px", color: t.sub }}>{p.min}</td>
                  <td style={{ padding: "10px 14px", whiteSpace: "nowrap" }}>{fmtKES(p.buy * p.qty)}</td>
                  <td style={{ padding: "10px 14px" }}><span style={{ fontSize: 10, fontWeight: 700, color: status.c, background: `${status.c}18`, padding: "3px 9px", borderRadius: 20, whiteSpace: "nowrap" }}>{status.l}</span></td>
                  <td style={{ padding: "10px 14px" }}>
                    <div style={{ display: "flex", gap: 6 }}>
                      <button onClick={() => onStockIn(p)} style={{ fontSize: 11, padding: "5px 10px", borderRadius: 6, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer", whiteSpace: "nowrap" }}>Stock In</button>
                      {isAdmin && (
                        confirmingRowId === p.id ? (
                          <>
                            <button onClick={() => setConfirmingRowId(null)} style={{ fontSize: 11, padding: "5px 8px", borderRadius: 6, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer" }}>Cancel</button>
                            <button onClick={() => { setProducts(list => list.filter(x => x.id !== p.id)); setConfirmingRowId(null); showToast("Product deleted"); }}
                              style={{ fontSize: 11, padding: "5px 8px", borderRadius: 6, border: "none", background: palette.danger, color: "#fff", cursor: "pointer", whiteSpace: "nowrap" }}>Confirm</button>
                          </>
                        ) : (
                          <button onClick={() => setConfirmingRowId(p.id)}
                            style={{ fontSize: 11, padding: "5px 8px", borderRadius: 6, border: `1px solid ${palette.danger}55`, background: "transparent", color: palette.danger, cursor: "pointer" }}>
                            <Trash2 size={11} />
                          </button>
                        )
                      )}
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        </div>
      </div>
    </div>
  );
}
function MiniStat({ t, label, value, tone }) {
  return (
    <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 14 }}>
      <div style={{ fontSize: 11, color: t.sub, fontWeight: 600, marginBottom: 6 }}>{label}</div>
      <div className="serif" style={{ fontSize: 17, fontWeight: 700, color: tone || t.text }}>{value}</div>
    </div>
  );
}
function StockInModal({ t, product, onClose, onConfirm }) {
  const [qty, setQty] = useState(12);
  return (
    <div style={{ position: "fixed", inset: 0, background: "#00000088", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 100 }}>
      <div style={{ width: 340, background: t.surface, color: t.text, borderRadius: 14, padding: 22 }}>
        <div className="serif" style={{ fontWeight: 700, fontSize: 15, marginBottom: 4 }}>Stock In</div>
        <div style={{ fontSize: 12.5, color: t.sub, marginBottom: 16 }}>{product.name}</div>
        <label style={{ fontSize: 11, fontWeight: 600, color: t.sub }}>Quantity received</label>
        <input type="number" value={qty} onChange={e => setQty(Number(e.target.value))}
          style={{ width: "100%", padding: "9px 10px", marginTop: 4, marginBottom: 16, borderRadius: 7, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontSize: 14 }} />
        <div style={{ display: "flex", gap: 8 }}>
          <button onClick={onClose} style={{ flex: 1, padding: 10, borderRadius: 8, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer" }}>Cancel</button>
          <button onClick={() => onConfirm(qty)} style={{ flex: 1, padding: 10, borderRadius: 8, border: "none", background: palette.wine, color: "#fff", fontWeight: 700, cursor: "pointer" }}>Confirm</button>
        </div>
      </div>
    </div>
  );
}

/* ---------------------------------- expenses ---------------------------------- */
const EXPENSE_CATEGORIES = ["Rent", "Transport", "Utilities", "Salaries", "Restocking", "Maintenance", "Marketing", "Other"];

function Expenses({ t, expenses, setExpenses, showToast, role }) {
  const canEdit = role === "Administrator" || role === "Manager";
  const [showAdd, setShowAdd] = useState(false);
  const [category, setCategory] = useState(EXPENSE_CATEGORIES[0]);
  const [note, setNote] = useState("");
  const [amount, setAmount] = useState("");
  const [date, setDate] = useState(() => new Date().toISOString().slice(0, 10));
  const [editing, setEditing] = useState(null);
  const [confirmingRowId, setConfirmingRowId] = useState(null);

  const now = new Date();
  const totals = useMemo(() => {
    let today = 0, month = 0, year = 0, all = 0;
    expenses.forEach(x => {
      const d = new Date(x.date);
      all += x.amount;
      if (d.getFullYear() === now.getFullYear()) {
        year += x.amount;
        if (d.getMonth() === now.getMonth()) {
          month += x.amount;
          if (d.toDateString() === now.toDateString()) today += x.amount;
        }
      }
    });
    return { today, month, year, all };
  }, [expenses]);

  const sorted = useMemo(() => [...expenses].sort((a, b) => new Date(b.date) - new Date(a.date)), [expenses]);

  const resetForm = () => { setCategory(EXPENSE_CATEGORIES[0]); setNote(""); setAmount(""); setDate(new Date().toISOString().slice(0, 10)); };

  const save = () => {
    const amt = Number(amount);
    if (!amt || amt <= 0 || !date) return;
    setExpenses(list => [...list, { id: Math.max(0, ...list.map(x => x.id)) + 1, category, note: note.trim(), amount: amt, date }]);
    resetForm(); setShowAdd(false); showToast("Expense recorded");
  };

  const saveEdit = () => {
    if (!editing) return;
    const amt = Number(editing.amount);
    if (!amt || amt <= 0 || !editing.date) return;
    setExpenses(list => list.map(x => x.id === editing.id ? { ...editing, amount: amt } : x));
    setEditing(null); showToast("Expense updated");
  };

  return (
    <div>
      <div className="four-col" style={{ marginBottom: 18 }}>
        <MiniStat t={t} label="Today's Expenses" value={fmtKES(totals.today)} tone={palette.danger} />
        <MiniStat t={t} label="This Month" value={fmtKES(totals.month)} tone={palette.danger} />
        <MiniStat t={t} label="This Year" value={fmtKES(totals.year)} tone={palette.danger} />
        <MiniStat t={t} label="All-Time Expenses" value={fmtKES(totals.all)} tone={palette.danger} />
      </div>

      {!canEdit && (
        <div style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 12, color: t.sub, background: `${palette.gold}14`, border: `1px solid ${palette.gold}33`, borderRadius: 8, padding: "8px 12px", marginBottom: 14 }}>
          <Lock size={12} /> Only Administrators and Managers can record or edit expenses.
        </div>
      )}

      {canEdit && (
        <div style={{ display: "flex", justifyContent: "flex-end", marginBottom: 14 }}>
          <button onClick={() => setShowAdd(s => !s)} style={{ display: "flex", alignItems: "center", gap: 6, padding: "9px 16px", borderRadius: 10, border: "none", background: palette.wine, color: "#fff", fontWeight: 600, fontSize: 13, cursor: "pointer" }}>
            <Plus size={15} /> Add Expense
          </button>
        </div>
      )}

      {showAdd && canEdit && (
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr 1fr auto", gap: 8, alignItems: "end", marginBottom: 14, background: t.surface, border: `1px solid ${t.border}`, borderRadius: 10, padding: 12 }}>
          <div>
            <div style={{ fontSize: 10.5, color: t.sub, marginBottom: 4, fontWeight: 600 }}>Category</div>
            <select value={category} onChange={e => setCategory(e.target.value)}
              style={{ width: "100%", padding: "8px 10px", borderRadius: 7, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontSize: 13 }}>
              {EXPENSE_CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
          <div>
            <div style={{ fontSize: 10.5, color: t.sub, marginBottom: 4, fontWeight: 600 }}>Note (optional)</div>
            <input value={note} onChange={e => setNote(e.target.value)} placeholder="e.g. July rent"
              style={{ width: "100%", padding: "8px 10px", borderRadius: 7, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontSize: 13 }} />
          </div>
          <div>
            <div style={{ fontSize: 10.5, color: t.sub, marginBottom: 4, fontWeight: 600 }}>Amount (KES)</div>
            <input type="number" value={amount} onChange={e => setAmount(e.target.value)} placeholder="0"
              style={{ width: "100%", padding: "8px 10px", borderRadius: 7, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontSize: 13 }} />
          </div>
          <div>
            <div style={{ fontSize: 10.5, color: t.sub, marginBottom: 4, fontWeight: 600 }}>Date</div>
            <input type="date" value={date} onChange={e => setDate(e.target.value)}
              style={{ width: "100%", padding: "8px 10px", borderRadius: 7, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontSize: 13 }} />
          </div>
          <button onClick={save} disabled={!amount || Number(amount) <= 0}
            style={{ padding: "9px 18px", borderRadius: 7, border: "none", background: (amount && Number(amount) > 0) ? palette.wine : `${palette.wine}55`, color: "#fff", fontWeight: 600, fontSize: 12.5, cursor: (amount && Number(amount) > 0) ? "pointer" : "not-allowed", whiteSpace: "nowrap" }}>
            Save
          </button>
        </div>
      )}

      <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, overflow: "hidden" }}>
        <div className="scroll-hint">Swipe left to see actions →</div>
        <div style={{ overflowX: "auto", WebkitOverflowScrolling: "touch" }}>
        <table style={{ width: "100%", minWidth: 560, borderCollapse: "collapse", fontSize: 12.5 }}>
          <thead>
            <tr style={{ background: `${palette.wine}0F`, textAlign: "left" }}>
              {["Date", "Category", "Note", "Amount", ""].map(h => <th key={h} style={{ padding: "10px 14px", fontWeight: 700, color: t.sub, fontSize: 11, whiteSpace: "nowrap" }}>{h}</th>)}
            </tr>
          </thead>
          <tbody>
            {sorted.length === 0 ? (
              <tr><td colSpan={5} style={{ padding: "18px 14px", color: t.sub, fontSize: 12.5 }}>No expenses recorded yet.</td></tr>
            ) : sorted.map(x => (
              <tr key={x.id} style={{ borderTop: `1px solid ${t.border}` }}>
                <td style={{ padding: "10px 14px", whiteSpace: "nowrap" }}>{new Date(x.date).toLocaleDateString()}</td>
                <td style={{ padding: "10px 14px", fontWeight: 600, whiteSpace: "nowrap" }}>{x.category}</td>
                <td style={{ padding: "10px 14px", color: t.sub }}>{x.note || "—"}</td>
                <td style={{ padding: "10px 14px", color: palette.danger, fontWeight: 600, whiteSpace: "nowrap" }}>{fmtKES(x.amount)}</td>
                <td style={{ padding: "10px 14px" }}>
                  {canEdit && (
                    confirmingRowId === x.id ? (
                      <div style={{ display: "flex", gap: 6 }}>
                        <button onClick={() => setConfirmingRowId(null)} style={{ fontSize: 11, padding: "5px 8px", borderRadius: 6, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer" }}>Cancel</button>
                        <button onClick={() => { setExpenses(list => list.filter(e => e.id !== x.id)); setConfirmingRowId(null); showToast("Expense deleted"); }}
                          style={{ fontSize: 11, padding: "5px 8px", borderRadius: 6, border: "none", background: palette.danger, color: "#fff", cursor: "pointer", whiteSpace: "nowrap" }}>Confirm</button>
                      </div>
                    ) : (
                      <div style={{ display: "flex", gap: 6 }}>
                        <button onClick={() => setEditing(x)} style={{ fontSize: 11, padding: "5px 10px", borderRadius: 6, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer", whiteSpace: "nowrap" }}>Edit</button>
                        <button onClick={() => setConfirmingRowId(x.id)} style={{ fontSize: 11, padding: "5px 8px", borderRadius: 6, border: `1px solid ${palette.danger}55`, background: "transparent", color: palette.danger, cursor: "pointer" }}>
                          <Trash2 size={11} />
                        </button>
                      </div>
                    )
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        </div>
      </div>

      {editing && (
        <div style={{ position: "fixed", inset: 0, background: "#00000088", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 100 }}>
          <div style={{ width: 380, background: t.surface, color: t.text, borderRadius: 14, padding: 22 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
              <div className="serif" style={{ fontWeight: 700, fontSize: 16 }}>Edit Expense</div>
              <button onClick={() => setEditing(null)} style={{ background: "none", border: "none", color: t.text, cursor: "pointer" }}><X size={18} /></button>
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
              <div style={{ gridColumn: "1 / -1" }}>
                <div style={{ fontSize: 10.5, color: t.sub, marginBottom: 4, fontWeight: 600 }}>Category</div>
                <select value={editing.category} onChange={e => setEditing(f => ({ ...f, category: e.target.value }))}
                  style={{ width: "100%", padding: "9px 10px", borderRadius: 7, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontSize: 13 }}>
                  {EXPENSE_CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <Field t={t} label="Note" full value={editing.note} onChange={v => setEditing(f => ({ ...f, note: v }))} />
              <Field t={t} label="Amount (KES)" type="number" value={editing.amount} onChange={v => setEditing(f => ({ ...f, amount: v }))} />
              <Field t={t} label="Date" type="date" value={editing.date} onChange={v => setEditing(f => ({ ...f, date: v }))} />
            </div>
            <button onClick={saveEdit} style={{ width: "100%", marginTop: 18, padding: 11, borderRadius: 9, border: "none", background: palette.wine, color: "#fff", fontWeight: 700, fontSize: 13.5, cursor: "pointer" }}>
              Save Changes
            </button>
            <button onClick={() => { setExpenses(list => list.filter(e => e.id !== editing.id)); setEditing(null); showToast("Expense removed"); }}
              style={{ width: "100%", marginTop: 8, padding: 10, borderRadius: 9, border: `1px solid ${palette.danger}55`, background: "transparent", color: palette.danger, fontWeight: 600, fontSize: 12.5, cursor: "pointer" }}>
              Remove Expense
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

/* ---------------------------------- reports ---------------------------------- */
function Reports({ t, products, sales, setSales, transactions, setTransactions, showToast, role, setReceipt, expenses }) {
  const [period, setPeriod] = useState("Weekly");
  const [selectedDay, setSelectedDay] = useState(null); // { key, date, total, count, sales } | null
  const isAdmin = role === "Administrator";
  const [confirmingReset, setConfirmingReset] = useState(false);

  const periodLabels = { Daily: "Today", Weekly: "This Week", Monthly: "This Month", Yearly: "This Year", All: "All Time" };

  // actually filter sales down to the selected period, instead of just labeling the button
  const periodSales = useMemo(() => {
    if (period === "All") return sales;
    const now = new Date();
    const startOfWeek = new Date(now); startOfWeek.setDate(now.getDate() - now.getDay()); startOfWeek.setHours(0, 0, 0, 0);
    return sales.filter(s => {
      const d = saleTimestamp(s);
      if (period === "Daily") return d.toDateString() === now.toDateString();
      if (period === "Weekly") return d >= startOfWeek;
      if (period === "Monthly") return d.getFullYear() === now.getFullYear() && d.getMonth() === now.getMonth();
      if (period === "Yearly") return d.getFullYear() === now.getFullYear();
      return true;
    });
  }, [sales, period]);

  // filter expenses down to the same selected period as sales, so profit figures line up
  const periodExpenses = useMemo(() => {
    const list = expenses || [];
    if (period === "All") return list;
    const now = new Date();
    const startOfWeek = new Date(now); startOfWeek.setDate(now.getDate() - now.getDay()); startOfWeek.setHours(0, 0, 0, 0);
    return list.filter(x => {
      const d = new Date(x.date);
      if (period === "Daily") return d.toDateString() === now.toDateString();
      if (period === "Weekly") return d >= startOfWeek;
      if (period === "Monthly") return d.getFullYear() === now.getFullYear() && d.getMonth() === now.getMonth();
      if (period === "Yearly") return d.getFullYear() === now.getFullYear();
      return true;
    });
  }, [expenses, period]);

  const stats = useMemo(() => {
    const revenue = periodSales.reduce((a, s) => a + s.total, 0);
    const discountTotal = periodSales.reduce((a, s) => a + s.discountAmt, 0);
    const vatTotal = periodSales.reduce((a, s) => a + s.vat, 0);
    const netSales = periodSales.reduce((a, s) => a + (s.subtotal - s.discountAmt), 0);
    const cogs = periodSales.reduce((a, s) => a + s.items.reduce((ia, it) => {
      const prod = products.find(p => p.id === it.id);
      return ia + it.qty * (prod ? prod.buy : 0);
    }, 0), 0);
    const grossProfit = netSales - cogs;
    const expenseTotal = periodExpenses.reduce((a, x) => a + x.amount, 0);
    const netProfit = grossProfit - expenseTotal;

    const productMap = {};
    periodSales.forEach(s => s.items.forEach(it => {
      if (!productMap[it.id]) productMap[it.id] = { name: it.name, qty: 0, revenue: 0 };
      productMap[it.id].qty += it.qty;
      productMap[it.id].revenue += it.qty * it.price;
    }));
    const topProducts = Object.values(productMap).sort((a, b) => b.qty - a.qty).slice(0, 6);

    const methodMap = {};
    periodSales.forEach(s => { methodMap[s.method] = (methodMap[s.method] || 0) + s.total; });
    const byMethod = Object.entries(methodMap).map(([method, total]) => ({ method, total }));

    // group into calendar days within the selected period, most recent first, each holding its own sales list
    const dailyMap = {};
    periodSales.forEach(s => {
      const d = saleTimestamp(s);
      const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
      if (!dailyMap[key]) dailyMap[key] = { key, date: d, total: 0, count: 0, sales: [] };
      dailyMap[key].total += s.total;
      dailyMap[key].count += 1;
      dailyMap[key].sales.push(s);
    });
    const dailyBreakdown = Object.values(dailyMap)
      .sort((a, b) => b.date - a.date)
      .map(d => ({ ...d, sales: d.sales.sort((a, b) => saleTimestamp(b) - saleTimestamp(a)) }));

    return { revenue, discountTotal, vatTotal, netSales, cogs, grossProfit, expenseTotal, netProfit, topProducts, byMethod, dailyBreakdown };
  }, [periodSales, products, periodExpenses]);

  const hasSales = periodSales.length > 0;

  return (
    <div>
      <div style={{ display: "flex", gap: 8, marginBottom: 18, flexWrap: "wrap" }}>
        {["Daily", "Weekly", "Monthly", "Yearly", "All"].map(p => (
          <button key={p} onClick={() => { setPeriod(p); showToast(`Showing ${periodLabels[p].toLowerCase()}`); }} style={{ padding: "8px 16px", borderRadius: 8, fontSize: 12.5, fontWeight: 600, cursor: "pointer",
            border: `1px solid ${period === p ? palette.wine : t.border}`, background: period === p ? palette.wine : "transparent", color: period === p ? "#fff" : t.text }}>
            {periodLabels[p]}
          </button>
        ))}
        <button onClick={() => showToast(hasSales ? "PDF report downloaded" : "No sales data to export yet")} style={{ marginLeft: isAdmin ? 0 : "auto", padding: "8px 14px", borderRadius: 8, fontSize: 12, fontWeight: 600, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer" }}>Export PDF</button>
        <button onClick={() => showToast(hasSales ? "Excel report downloaded" : "No sales data to export yet")} style={{ padding: "8px 14px", borderRadius: 8, fontSize: 12, fontWeight: 600, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer" }}>Export Excel</button>
        {isAdmin && (
          !confirmingReset ? (
            <button onClick={() => setConfirmingReset(true)} disabled={!sales.length}
              style={{ marginLeft: "auto", display: "flex", alignItems: "center", gap: 6, padding: "8px 14px", borderRadius: 8, fontSize: 12, fontWeight: 600, border: `1px solid ${palette.danger}55`, background: "transparent", color: sales.length ? palette.danger : t.sub, cursor: sales.length ? "pointer" : "not-allowed" }}>
              <Trash2 size={13} /> Reset Report Data
            </button>
          ) : (
            <div style={{ marginLeft: "auto", display: "flex", alignItems: "center", gap: 8, fontSize: 12, color: t.sub }}>
              <span>Clear all sales history?</span>
              <button onClick={() => setConfirmingReset(false)} style={{ padding: "7px 12px", borderRadius: 7, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer", fontSize: 12 }}>Cancel</button>
              <button onClick={() => { setSales([]); setTransactions([]); setConfirmingReset(false); showToast("Report data reset"); }}
                style={{ padding: "7px 12px", borderRadius: 7, border: "none", background: palette.danger, color: "#fff", fontWeight: 700, cursor: "pointer", fontSize: 12 }}>Confirm Reset</button>
            </div>
          )
        )}
      </div>

      <div style={{ fontSize: 11.5, color: t.sub, marginBottom: 10 }}>
        {hasSales ? `Based on ${periodSales.length} sale${periodSales.length > 1 ? "s" : ""} · ${periodLabels[period]}.` : `No sales recorded for ${periodLabels[period].toLowerCase()} — figures below will populate as sales are completed in New Sale.`}
      </div>

      <div className="four-col" style={{ marginBottom: 18 }}>
        <MiniStat t={t} label="Revenue" value={fmtKES(stats.revenue)} />
        <MiniStat t={t} label="Cost of Goods Sold" value={fmtKES(stats.cogs)} />
        <MiniStat t={t} label="Gross Profit" value={fmtKES(stats.grossProfit)} tone={stats.grossProfit >= 0 ? palette.success : palette.danger} />
        <MiniStat t={t} label="Expenses" value={fmtKES(stats.expenseTotal)} tone={palette.danger} />
        <MiniStat t={t} label="Net Profit" value={fmtKES(stats.netProfit)} tone={stats.netProfit >= 0 ? palette.success : palette.danger} />
        <MiniStat t={t} label="VAT Collected" value={fmtKES(stats.vatTotal)} />
      </div>

      <div className="two-col-wide" style={{ marginBottom: 16 }}>
        <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 18 }}>
          <div className="serif" style={{ fontWeight: 700, marginBottom: 12, fontSize: 14.5 }}>Revenue by Payment Method</div>
          {hasSales ? (
            <ResponsiveContainer width="100%" height={230}>
              <BarChart data={stats.byMethod}>
                <CartesianGrid strokeDasharray="3 3" stroke={t.border} />
                <XAxis dataKey="method" stroke={t.sub} fontSize={11} />
                <YAxis stroke={t.sub} fontSize={11} tickFormatter={(v) => `${v / 1000}k`} />
                <Tooltip formatter={(v) => fmtKES(v)} contentStyle={{ background: t.surface, border: `1px solid ${t.border}`, fontSize: 12 }} />
                <Bar dataKey="total" fill={palette.wine} radius={[6, 6, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          ) : (
            <div style={{ height: 230, display: "flex", alignItems: "center", justifyContent: "center", color: t.sub, fontSize: 12.5 }}>No sales yet</div>
          )}
        </div>
        <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 18 }}>
          <div className="serif" style={{ fontWeight: 700, marginBottom: 12, fontSize: 14.5 }}>Best Selling Products</div>
          {stats.topProducts.length === 0 && <div style={{ color: t.sub, fontSize: 12.5 }}>No sales yet</div>}
          {stats.topProducts.map((p, i) => (
            <div key={p.name} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 0", borderBottom: `1px solid ${t.border}` }}>
              <span className="serif" style={{ fontSize: 13, fontWeight: 700, color: palette.gold, width: 16 }}>{i + 1}</span>
              <span style={{ fontSize: 12.5, flex: 1 }}>{p.name}</span>
              <span style={{ fontSize: 11, color: t.sub, marginRight: 8 }}>{p.qty} sold</span>
              <span style={{ fontSize: 12, fontWeight: 700 }}>{fmtKES(p.revenue)}</span>
            </div>
          ))}
        </div>
      </div>

      <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 18 }}>
        <div className="serif" style={{ fontWeight: 700, marginBottom: 4, fontSize: 14.5 }}>Sales by Date</div>
        <div style={{ fontSize: 11.5, color: t.sub, marginBottom: 12 }}>Tap any date to see the individual sales made that day.</div>
        {stats.dailyBreakdown.length === 0 ? (
          <div style={{ color: t.sub, fontSize: 12.5 }}>No sales recorded for {periodLabels[period].toLowerCase()}.</div>
        ) : (
          <div style={{ maxHeight: 320, overflowY: "auto" }}>
            {stats.dailyBreakdown.map(d => (
              <button key={d.key} onClick={() => setSelectedDay(d)}
                style={{ display: "flex", justifyContent: "space-between", alignItems: "center", width: "100%", padding: "10px 2px", borderBottom: `1px solid ${t.border}`, background: "none", border: "none", borderBottomWidth: 1, borderBottomStyle: "solid", borderBottomColor: t.border, textAlign: "left", cursor: "pointer", color: t.text }}>
                <div>
                  <div style={{ fontWeight: 600, fontSize: 13 }}>{d.date.toLocaleDateString(undefined, { weekday: "short", day: "numeric", month: "short", year: "numeric" })}</div>
                  <div style={{ color: t.sub, fontSize: 11 }}>{d.count} sale{d.count === 1 ? "" : "s"}</div>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                  <span style={{ fontWeight: 700, fontSize: 13, color: palette.wine }}>{fmtKES(d.total)}</span>
                  <span style={{ color: t.sub, fontSize: 15 }}>›</span>
                </div>
              </button>
            ))}
          </div>
        )}
      </div>

      {selectedDay && (
        <DayDetailModal t={t} day={selectedDay} onClose={() => setSelectedDay(null)}
          onOpenReceipt={(sale) => { setSelectedDay(null); setReceipt(sale); }} />
      )}
    </div>
  );
}

function DayDetailModal({ t, day, onClose, onOpenReceipt }) {
  return (
    <div style={{ position: "fixed", inset: 0, background: "#00000088", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 100 }}>
      <div style={{ width: 420, maxWidth: "92vw", maxHeight: "80vh", overflowY: "auto", background: t.surface, color: t.text, borderRadius: 14, padding: 22 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 4 }}>
          <div>
            <div className="serif" style={{ fontWeight: 700, fontSize: 16 }}>
              {day.date.toLocaleDateString(undefined, { weekday: "long", day: "numeric", month: "long", year: "numeric" })}
            </div>
            <div style={{ fontSize: 12, color: t.sub, marginTop: 2 }}>{day.count} sale{day.count === 1 ? "" : "s"} · {fmtKES(day.total)} total</div>
          </div>
          <button onClick={onClose} style={{ background: "none", border: "none", cursor: "pointer", color: t.sub, padding: 4 }}><X size={18} /></button>
        </div>
        <div style={{ marginTop: 14 }}>
          {day.sales.map(s => (
            <button key={s.id} onClick={() => onOpenReceipt(s)}
              style={{ display: "flex", justifyContent: "space-between", alignItems: "center", width: "100%", padding: "10px 2px", background: "none", border: "none", borderBottom: `1px solid ${t.border}`, textAlign: "left", cursor: "pointer", color: t.text }}>
              <div>
                <div style={{ fontWeight: 600, fontSize: 12.5 }}>{s.id}</div>
                <div style={{ color: t.sub, fontSize: 11 }}>{s.time} · {s.cashier} · {s.method}</div>
              </div>
              <span style={{ fontWeight: 700, fontSize: 12.5, color: palette.wine }}>{fmtKES(s.total)}</span>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}

/* ---------------------------------- customers ---------------------------------- */
function Customers({ t, customers, setCustomers, showToast, role }) {
  const [showAdd, setShowAdd] = useState(false);
  const [name, setName] = useState(""); const [phone, setPhone] = useState("");
  const [editing, setEditing] = useState(null);
  const canEdit = role === "Administrator";
  return (
    <div>
      <div style={{ display: "flex", justifyContent: "flex-end", marginBottom: 14 }}>
        <button onClick={() => setShowAdd(s => !s)} style={{ display: "flex", alignItems: "center", gap: 6, padding: "9px 16px", borderRadius: 10, border: "none", background: palette.wine, color: "#fff", fontWeight: 600, fontSize: 13, cursor: "pointer" }}>
          <Plus size={15} /> Add Customer
        </button>
      </div>
      {showAdd && (
        <div style={{ display: "flex", gap: 8, marginBottom: 14, background: t.surface, border: `1px solid ${t.border}`, borderRadius: 10, padding: 12 }}>
          <input placeholder="Full name" value={name} onChange={e => setName(e.target.value)} style={{ flex: 1, padding: "8px 10px", borderRadius: 7, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontSize: 13 }} />
          <input placeholder="Phone number" value={phone} onChange={e => setPhone(e.target.value)} style={{ flex: 1, padding: "8px 10px", borderRadius: 7, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontSize: 13 }} />
          <button onClick={() => {
            if (!name.trim()) return;
            setCustomers(c => [...c, { id: Math.max(0, ...c.map(x => x.id)) + 1, name, phone: phone || "-", points: 0, balance: 0, visits: 0 }]);
            setName(""); setPhone(""); setShowAdd(false); showToast("Customer added");
          }} style={{ padding: "8px 16px", borderRadius: 7, border: "none", background: palette.wine, color: "#fff", fontWeight: 600, fontSize: 12.5, cursor: "pointer" }}>Save</button>
        </div>
      )}
      {!canEdit && (
        <div style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 12, color: t.sub, background: `${palette.gold}14`, border: `1px solid ${palette.gold}33`, borderRadius: 8, padding: "8px 12px", marginBottom: 12 }}>
          <Lock size={12} /> Only Administrators can edit customer records.
        </div>
      )}
      <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, overflow: "hidden" }}>
        <div className="scroll-hint">Swipe left to see balance &amp; actions →</div>
        <div style={{ overflowX: "auto", WebkitOverflowScrolling: "touch" }}>
        <table style={{ width: "100%", minWidth: 560, borderCollapse: "collapse", fontSize: 12.5 }}>
          <thead>
            <tr style={{ background: `${palette.wine}0F`, textAlign: "left" }}>
              {["Name", "Phone", "Loyalty Points", "Outstanding Balance", "Visits", ""].map(h => <th key={h} style={{ padding: "10px 14px", fontWeight: 700, color: t.sub, fontSize: 11, whiteSpace: "nowrap" }}>{h}</th>)}
            </tr>
          </thead>
          <tbody>
            {customers.map(c => (
              <tr key={c.id} style={{ borderTop: `1px solid ${t.border}` }}>
                <td style={{ padding: "10px 14px", fontWeight: 600, whiteSpace: "nowrap" }}>{c.name}</td>
                <td style={{ padding: "10px 14px", color: t.sub, whiteSpace: "nowrap" }}>{c.phone}</td>
                <td style={{ padding: "10px 14px" }}>{c.points}</td>
                <td style={{ padding: "10px 14px", color: c.balance > 0 ? palette.danger : t.sub, whiteSpace: "nowrap" }}>{fmtKES(c.balance)}</td>
                <td style={{ padding: "10px 14px" }}>{c.visits}</td>
                <td style={{ padding: "10px 14px" }}>
                  {canEdit && (
                    <button onClick={() => setEditing(c)} style={{ fontSize: 11, padding: "5px 10px", borderRadius: 6, border: `1px solid ${t.border}`, background: "transparent", color: t.text, cursor: "pointer", whiteSpace: "nowrap" }}>Edit</button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        </div>
      </div>
      {editing && (
        <CustomerModal t={t} data={editing} onClose={() => setEditing(null)}
          onSave={(updated) => {
            setCustomers(list => list.map(x => x.id === updated.id ? updated : x));
            setEditing(null); showToast("Customer updated");
          }}
          onDelete={(id) => {
            setCustomers(list => list.filter(x => x.id !== id));
            setEditing(null); showToast("Customer removed");
          }} />
      )}
    </div>
  );
}

function CustomerModal({ t, data, onClose, onSave, onDelete }) {
  const [form, setForm] = useState(data);
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));
  const valid = form.name && form.name.trim().length > 0;
  return (
    <div style={{ position: "fixed", inset: 0, background: "#00000088", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 100 }}>
      <div style={{ width: 380, background: t.surface, color: t.text, borderRadius: 14, padding: 22 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <div className="serif" style={{ fontWeight: 700, fontSize: 16 }}>Edit Customer</div>
          <button onClick={onClose} style={{ background: "none", border: "none", color: t.text, cursor: "pointer" }}><X size={18} /></button>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
          <Field t={t} label="Full Name" full value={form.name} onChange={v => set("name", v)} />
          <Field t={t} label="Phone Number" full value={form.phone} onChange={v => set("phone", v)} />
          <Field t={t} label="Loyalty Points" type="number" value={form.points} onChange={v => set("points", v)} />
          <Field t={t} label="Outstanding Balance (KES)" type="number" value={form.balance} onChange={v => set("balance", v)} />
        </div>
        <button disabled={!valid} onClick={() => onSave({ ...form, points: Number(form.points) || 0, balance: Number(form.balance) || 0 })}
          style={{ width: "100%", marginTop: 18, padding: 11, borderRadius: 9, border: "none", background: valid ? palette.wine : `${palette.wine}55`, color: "#fff", fontWeight: 700, fontSize: 13.5, cursor: valid ? "pointer" : "not-allowed" }}>
          Save Changes
        </button>
        {data.id !== 1 && (
          <button onClick={() => onDelete(data.id)}
            style={{ width: "100%", marginTop: 8, padding: 10, borderRadius: 9, border: `1px solid ${palette.danger}55`, background: "transparent", color: palette.danger, fontWeight: 600, fontSize: 12.5, cursor: "pointer" }}>
            Remove Customer
          </button>
        )}
      </div>
    </div>
  );
}

/* ---------------------------------- settings ---------------------------------- */
function SettingsPanel({ t, role, businessInfo, setBusinessInfo, showToast, printer, connectPrinter, disconnectPrinter,
  products, setProducts, categories, setCategories, customers, setCustomers, transactions, setTransactions, sales, setSales,
  expenses, setExpenses, staffAccounts, setStaffAccounts, currentUserEmail }) {
  const [form, setForm] = useState(businessInfo);
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));
  const dirty = JSON.stringify(form) !== JSON.stringify(businessInfo);
  const valid = form.name.trim().length > 0 && form.currency.trim().length > 0;

  const save = () => {
    if (!valid) return;
    setBusinessInfo({ ...form, vatRate: Number(form.vatRate) || 0 });
    showToast("Business settings saved");
  };

  return (
    <div style={{ maxWidth: 560 }}>
      <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 20, marginBottom: 16 }}>
        <div className="serif" style={{ fontWeight: 700, fontSize: 15, marginBottom: 14 }}>Business Information</div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
          <Field t={t} label="Business Name" value={form.name} onChange={v => set("name", v)} full />
          <Field t={t} label="Address" value={form.address} onChange={v => set("address", v)} full />
          <Field t={t} label="Currency" value={form.currency} onChange={v => set("currency", v)} />
          <Field t={t} label="VAT Rate (%)" type="number" value={form.vatRate} onChange={v => set("vatRate", v)} />
          <Field t={t} label="Till Number" value={form.till} onChange={v => set("till", v)} />
          <Field t={t} label="Phone" value={form.phone} onChange={v => set("phone", v)} />
        </div>
        <button disabled={!valid || !dirty} onClick={save}
          style={{ marginTop: 16, padding: "10px 20px", borderRadius: 9, border: "none",
            background: (valid && dirty) ? palette.wine : `${palette.wine}55`, color: "#fff", fontWeight: 700, fontSize: 13, cursor: (valid && dirty) ? "pointer" : "not-allowed" }}>
          {dirty ? "Save Changes" : "Saved"}
        </button>
      </div>
      <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 20, marginBottom: 16 }}>
        <div className="serif" style={{ fontWeight: 700, fontSize: 15, marginBottom: 10 }}>Bluetooth Printer</div>
        <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 14 }}>
          <span style={{ width: 8, height: 8, borderRadius: "50%", background: printer ? palette.success : t.sub, flexShrink: 0 }} />
          <span style={{ fontSize: 12.5, color: t.sub }}>{printer ? `Connected: ${printer.name}` : "Not connected"}</span>
        </div>
        {printer ? (
          <button onClick={disconnectPrinter} style={{ padding: "9px 16px", borderRadius: 9, border: `1px solid ${palette.danger}55`, background: "transparent", color: palette.danger, fontWeight: 600, fontSize: 12.5, cursor: "pointer" }}>
            Disconnect
          </button>
        ) : (
          <button onClick={connectPrinter} style={{ display: "flex", alignItems: "center", gap: 6, padding: "9px 16px", borderRadius: 9, border: "none", background: palette.wine, color: "#fff", fontWeight: 600, fontSize: 12.5, cursor: "pointer" }}>
            <Bluetooth size={14} /> Connect Printer
          </button>
        )}
        <div style={{ fontSize: 11, color: t.sub, marginTop: 12 }}>
          Works with 58mm Bluetooth thermal printers like the P58E. Requires Chrome on Android or desktop — pair once here, or connect directly from the receipt screen when completing a sale.
        </div>
      </div>
      <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 20, marginBottom: role === "Administrator" ? 16 : 0 }}>
        <div className="serif" style={{ fontWeight: 700, fontSize: 15, marginBottom: 10 }}>Access</div>
        <div style={{ fontSize: 12.5, color: t.sub }}>Signed in as <strong style={{ color: t.text }}>{currentUserEmail}</strong> ({role}). Settings and user management are restricted to Administrators. Changes here apply to VAT calculations at checkout and the printed receipt.</div>
      </div>
      {role === "Administrator" && (
        <DataSyncPanel t={t} showToast={showToast}
          products={products} setProducts={setProducts}
          categories={categories} setCategories={setCategories}
          customers={customers} setCustomers={setCustomers}
          transactions={transactions} setTransactions={setTransactions}
          sales={sales} setSales={setSales}
          expenses={expenses} setExpenses={setExpenses}
          staffAccounts={staffAccounts} setStaffAccounts={setStaffAccounts}
          businessInfo={businessInfo} setBusinessInfo={setBusinessInfo} />
      )}
      {role === "Administrator" && (
        <StaffAccountsPanel t={t} staffAccounts={staffAccounts} setStaffAccounts={setStaffAccounts}
          currentUserEmail={currentUserEmail} showToast={showToast} />
      )}
      <DataDangerZone t={t} role={role} products={products} setProducts={setProducts} customers={customers} setCustomers={setCustomers}
        transactions={transactions} setTransactions={setTransactions} sales={sales} setSales={setSales}
        expenses={expenses} setExpenses={setExpenses} showToast={showToast} />
    </div>
  );
}

/* ---------------------------------- data sync: export / import backup ---------------------------------- */
function DataSyncPanel({ t, showToast, products, setProducts, categories, setCategories, customers, setCustomers,
  transactions, setTransactions, sales, setSales, expenses, setExpenses, staffAccounts, setStaffAccounts,
  businessInfo, setBusinessInfo }) {
  const fileInputRef = useRef(null);
  const [pendingImport, setPendingImport] = useState(null);
  const [cloudStatus, setCloudStatus] = useState(() => window.__musorichoDb ? "connected" : "connecting");

  useEffect(() => {
    if (window.__musorichoDb) { setCloudStatus("connected"); return; }
    const handler = () => setCloudStatus("connected");
    window.addEventListener("musoricho-firebase-ready", handler, { once: true });
    const timeout = setTimeout(() => setCloudStatus(s => s === "connecting" ? "offline" : s), 6000);
    return () => { window.removeEventListener("musoricho-firebase-ready", handler); clearTimeout(timeout); };
  }, []);

  const exportData = () => {
    const backup = {
      app: "MUSORICHO POS", version: 2, exportedAt: new Date().toISOString(),
      products, categories, customers, transactions, sales, expenses, staffAccounts, businessInfo,
    };
    const blob = new Blob([JSON.stringify(backup, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    const stamp = new Date().toISOString().slice(0, 10);
    a.href = url;
    a.download = `musoricho-backup-${stamp}.json`;
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);
    showToast("Backup file downloaded");
  };

  const pickFile = () => fileInputRef.current?.click();

  const onFileSelected = (e) => {
    const file = e.target.files?.[0];
    e.target.value = "";
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      try {
        const data = JSON.parse(reader.result);
        if (!data || data.app !== "MUSORICHO POS") { showToast("That doesn't look like a MUSORICHO backup file"); return; }
        setPendingImport(data);
      } catch (err) {
        showToast("Couldn't read that file — is it a valid backup .json?");
      }
    };
    reader.readAsText(file);
  };

  const confirmImport = () => {
    const d = pendingImport;
    if (!d) return;
    if (d.products) setProducts(d.products);
    if (d.categories) setCategories(d.categories);
    if (d.customers) setCustomers(d.customers);
    if (d.transactions) setTransactions(d.transactions);
    if (d.sales) setSales(d.sales);
    if (d.expenses) setExpenses(d.expenses);
    if (d.staffAccounts) setStaffAccounts(d.staffAccounts);
    if (d.businessInfo) setBusinessInfo(d.businessInfo);
    setPendingImport(null);
    showToast("Data imported — this device is now up to date");
  };

  return (
    <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 20, marginBottom: 16 }}>
      <div className="serif" style={{ fontWeight: 700, fontSize: 15, marginBottom: 6 }}>Data Sync (Backup &amp; Restore)</div>

      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 14 }}>
        <span style={{ width: 8, height: 8, borderRadius: 99, background: cloudStatus === "connected" ? palette.success : cloudStatus === "offline" ? palette.danger : palette.gold }} />
        <span style={{ fontSize: 12, fontWeight: 700, color: t.text }}>
          {cloudStatus === "connected" ? "Cloud sync: connected — this device shares live data with your other devices" :
           cloudStatus === "offline" ? "Cloud sync: unavailable — using this device only for now" :
           "Cloud sync: connecting…"}
        </span>
      </div>

      <div style={{ fontSize: 12, color: t.sub, marginBottom: 16 }}>
        When cloud sync is connected, changes made on any device (computer, phone, etc.) appear automatically on the others within a second or two. You can still use Export/Import below as a manual backup or to move data to a brand-new device.
      </div>

      <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
        <button onClick={exportData} style={{ display: "flex", alignItems: "center", gap: 8, padding: "10px 18px", borderRadius: 9, border: "none", background: palette.wine, color: "#fff", fontWeight: 700, fontSize: 13, cursor: "pointer" }}>
          <Download size={15} /> Export Backup
        </button>
        <button onClick={pickFile} style={{ display: "flex", alignItems: "center", gap: 8, padding: "10px 18px", borderRadius: 9, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontWeight: 700, fontSize: 13, cursor: "pointer" }}>
          <Upload size={15} /> Import Backup
        </button>
        <input ref={fileInputRef} type="file" accept="application/json,.json" onChange={onFileSelected} style={{ display: "none" }} />
      </div>

      {pendingImport && (
        <div style={{ marginTop: 16, padding: 14, borderRadius: 10, border: `1px solid ${palette.wine}`, background: `${palette.wine}10` }}>
          <div style={{ fontSize: 12.5, fontWeight: 700, color: t.text, marginBottom: 6 }}>Replace this device's data?</div>
          <div style={{ fontSize: 11.5, color: t.sub, marginBottom: 4 }}>
            Backup from {pendingImport.exportedAt ? new Date(pendingImport.exportedAt).toLocaleString() : "unknown date"}.
          </div>
          <div style={{ fontSize: 11.5, color: t.sub, marginBottom: 12 }}>
            This will overwrite products, categories, customers, transactions, sales, staff accounts, and business info currently on this device. This can't be undone.
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={confirmImport} style={{ flex: 1, padding: 9, borderRadius: 8, border: "none", background: palette.wine, color: "#fff", fontWeight: 700, fontSize: 12.5, cursor: "pointer" }}>
              Yes, Replace Data
            </button>
            <button onClick={() => setPendingImport(null)} style={{ flex: 1, padding: 9, borderRadius: 8, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontWeight: 700, fontSize: 12.5, cursor: "pointer" }}>
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

/* ---------------------------------- staff accounts: who can sign in, and as what role ---------------------------------- */
function StaffAccountsPanel({ t, staffAccounts, setStaffAccounts, currentUserEmail, showToast }) {
  const [newEmail, setNewEmail] = useState("");
  const [newRole, setNewRole] = useState("Cashier");

  const admins = Object.entries(staffAccounts).filter(([, r]) => r === "Administrator");

  const addAccount = () => {
    const email = newEmail.trim().toLowerCase();
    if (!email || !email.includes("@")) { showToast("Enter a valid email address"); return; }
    if (Object.keys(staffAccounts).some(e => e.toLowerCase() === email)) { showToast("That email is already registered"); return; }
    setStaffAccounts(sa => ({ ...sa, [email]: newRole }));
    setNewEmail("");
    showToast(`${email} added as ${newRole}`);
  };

  const changeRole = (email, role) => {
    if (email.toLowerCase() === (currentUserEmail || "").toLowerCase() && role !== "Administrator" && admins.length <= 1) {
      showToast("You can't remove your own Administrator access — ask another admin, or add one first");
      return;
    }
    setStaffAccounts(sa => ({ ...sa, [email]: role }));
  };

  const removeAccount = (email) => {
    if (email.toLowerCase() === (currentUserEmail || "").toLowerCase()) { showToast("You can't remove your own account while signed in"); return; }
    if (staffAccounts[email] === "Administrator" && admins.length <= 1) { showToast("At least one Administrator must remain"); return; }
    setStaffAccounts(sa => { const next = { ...sa }; delete next[email]; return next; });
    showToast(`${email} removed`);
  };

  return (
    <div style={{ background: t.surface, border: `1px solid ${t.border}`, borderRadius: 12, padding: 20, marginBottom: 16 }}>
      <div className="serif" style={{ fontWeight: 700, fontSize: 15, marginBottom: 6 }}>Staff Accounts</div>
      <div style={{ fontSize: 12, color: t.sub, marginBottom: 16 }}>
        Only Google accounts listed here can sign in to this POS. Add a staff member's Google email and choose their role — they can then sign in with "Sign in with Google" on any device.
      </div>

      <div style={{ display: "flex", gap: 8, marginBottom: 18, flexWrap: "wrap" }}>
        <input value={newEmail} onChange={e => setNewEmail(e.target.value)} onKeyDown={e => { if (e.key === "Enter") addAccount(); }}
          placeholder="staffmember@gmail.com" style={{ flex: 1, minWidth: 200, padding: "9px 12px", borderRadius: 8, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontSize: 13 }} />
        <select value={newRole} onChange={e => setNewRole(e.target.value)} style={{ padding: "9px 12px", borderRadius: 8, border: `1px solid ${t.border}`, background: t.surface, color: t.text, fontSize: 13 }}>
          <option>Cashier</option>
          <option>Manager</option>
          <option>Administrator</option>
        </select>
        <button onClick={addAccount} style={{ display: "flex", alignItems: "center", gap: 6, padding: "9px 16px", borderRadius: 8, border: "none", background: palette.wine, color: "#fff", fontWeight: 700, fontSize: 13, cursor: "pointer" }}>
          <Plus size={14} /> Add
        </button>
      </div>

      {Object.keys(staffAccounts).length === 0 ? (
        <div style={{ fontSize: 12.5, color: t.sub }}>No staff accounts yet.</div>
      ) : (
        Object.entries(staffAccounts).map(([email, r]) => (
          <div key={email} style={{ display: "flex", alignItems: "center", gap: 10, padding: "10px 0", borderBottom: `1px solid ${t.border}` }}>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 13, fontWeight: 600, color: t.text, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                {email}{email.toLowerCase() === (currentUserEmail || "").toLowerCase() ? " (you)" : ""}
              </div>
            </div>
            <select value={r} onChange={e => changeRole(email, e.target.value)} style={{ padding: "6px 10px", borderRadius: 7, border: `1px solid ${t.border}`, background: t.surface, color: t.text, fontSize: 12.5 }}>
              <option>Cashier</option>
              <option>Manager</option>
              <option>Administrator</option>
            </select>
            <button onClick={() => removeAccount(email)} title="Remove" style={{ background: "none", border: "none", color: palette.danger, cursor: "pointer", padding: 4 }}>
              <Trash2 size={15} />
            </button>
          </div>
        ))
      )}
    </div>
  );
}

/* ---------------------------------- admin data management ---------------------------------- */
function DataDangerZone({ t, role, products, setProducts, customers, setCustomers, transactions, setTransactions, sales, setSales, expenses, setExpenses, showToast }) {
  const [pending, setPending] = useState(null);
  const [typedConfirm, setTypedConfirm] = useState("");
  if (role !== "Administrator") return null;

  const actions = [
    {
      key: "inventory",
      label: "Reset Inventory",
      desc: `Permanently deletes all ${products.length} product${products.length === 1 ? "" : "s"} and their stock records.`,
      disabled: products.length === 0,
      run: () => { setProducts([]); showToast("Inventory reset"); }
    },
    {
      key: "reports",
      label: "Reset Sales & Reports",
      desc: `Clears ${sales.length} recorded sale${sales.length === 1 ? "" : "s"} and the full transaction log. Product stock is not affected.`,
      disabled: sales.length === 0 && transactions.length === 0,
      run: () => { setSales([]); setTransactions([]); showToast("Sales & reports data reset"); }
    },
    {
      key: "expenses",
      label: "Reset Expenses",
      desc: `Deletes all ${expenses.length} recorded expense${expenses.length === 1 ? "" : "s"}. Sales and profit history are not affected.`,
      disabled: expenses.length === 0,
      run: () => { setExpenses([]); showToast("Expenses reset"); }
    },
    {
      key: "customers",
      label: "Reset Customers",
      desc: `Removes all customers except Walk-in Customer (currently ${customers.length} on file).`,
      disabled: customers.length <= 1,
      run: () => { setCustomers(initialCustomers); showToast("Customers reset"); }
    },
    {
      key: "all",
      label: "Factory Reset All Data",
      desc: "Deletes every product, customer, sale, expense, and transaction on this device and restores default data. This cannot be undone.",
      disabled: false,
      run: () => {
        setProducts([]); setCustomers(initialCustomers); setTransactions([]); setSales([]); setExpenses([]);
        showToast("All data has been reset");
      }
    }
  ];

  return (
    <div style={{ background: t.surface, border: `1px solid ${palette.danger}55`, borderRadius: 12, padding: 20 }}>
      <div className="serif" style={{ fontWeight: 700, fontSize: 15, marginBottom: 4, color: palette.danger, display: "flex", alignItems: "center", gap: 8 }}>
        <AlertTriangle size={16} /> Danger Zone
      </div>
      <div style={{ fontSize: 12, color: t.sub, marginBottom: 16 }}>
        These actions permanently delete data on this device for all cashiers and cannot be undone. Only Administrators can see this section.
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {actions.map(a => (
          <div key={a.key} style={{ border: `1px solid ${t.border}`, borderRadius: 10, padding: 14 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 10, flexWrap: "wrap" }}>
              <div style={{ flex: 1, minWidth: 220 }}>
                <div style={{ fontWeight: 700, fontSize: 13 }}>{a.label}</div>
                <div style={{ fontSize: 11.5, color: t.sub, marginTop: 2 }}>{a.desc}</div>
              </div>
              {pending !== a.key ? (
                <button onClick={() => { setPending(a.key); setTypedConfirm(""); }} disabled={a.disabled}
                  style={{ padding: "8px 14px", borderRadius: 8, border: `1px solid ${palette.danger}55`, background: "transparent", color: a.disabled ? t.sub : palette.danger, fontWeight: 600, fontSize: 12, cursor: a.disabled ? "not-allowed" : "pointer", whiteSpace: "nowrap" }}>
                  {a.label}
                </button>
              ) : (
                <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
                  <input value={typedConfirm} onChange={e => setTypedConfirm(e.target.value)} placeholder='Type "DELETE" to confirm'
                    style={{ padding: "8px 10px", borderRadius: 7, border: `1px solid ${palette.danger}55`, background: "transparent", color: t.text, fontSize: 12, width: 160 }} />
                  <button onClick={() => setPending(null)} style={{ padding: "8px 12px", borderRadius: 8, border: `1px solid ${t.border}`, background: "transparent", color: t.text, fontWeight: 600, fontSize: 12, cursor: "pointer" }}>Cancel</button>
                  <button onClick={() => { a.run(); setPending(null); setTypedConfirm(""); }} disabled={typedConfirm.trim().toUpperCase() !== "DELETE"}
                    style={{ padding: "8px 12px", borderRadius: 8, border: "none", background: typedConfirm.trim().toUpperCase() === "DELETE" ? palette.danger : `${palette.danger}55`, color: "#fff", fontWeight: 700, fontSize: 12, cursor: typedConfirm.trim().toUpperCase() === "DELETE" ? "pointer" : "not-allowed" }}>
                    Confirm Delete
                  </button>
                </div>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}


/* ---------------------------------- mount ---------------------------------- */
const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(<App />);
